// Optimized kernel using tiling, with a fast-path for blocks that are fully in-bound.
__global__ void matmul_tiled_optimized_kernel(const float* __restrict__ A, 
                                               const float* __restrict__ B, 
                                               float* __restrict__ C, 
                                               int N) {
    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int row = blockIdx.y * TILE_SIZE + ty;
    const int col = blockIdx.x * TILE_SIZE + tx;

    // Determine if the entire block lies fully within matrix boundaries
    bool fullTile = (((blockIdx.x + 1) * TILE_SIZE) <= N) && (((blockIdx.y + 1) * TILE_SIZE) <= N);

    float C_value = 0.0f;
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int numTiles = (N + TILE_SIZE - 1) / TILE_SIZE;
    for (int m = 0; m < numTiles; m++) {
        int tiledColA = m * TILE_SIZE + tx;
        int tiledRowB = m * TILE_SIZE + ty;

        if (fullTile) {
            // Fast-path: no boundary checks needed
            As[ty][tx] = A[row * N + tiledColA];
            Bs[ty][tx] = B[tiledRowB * N + col];
        } else {
            // Use conditional loads when the tile may cross the matrix boundary
            As[ty][tx] = (row < N && tiledColA < N) ? A[row * N + tiledColA] : 0.0f;
            Bs[ty][tx] = (col < N && tiledRowB < N) ? B[tiledRowB * N + col] : 0.0f;
        }
        __syncthreads();

        #pragma unroll
        for (int k = 0; k < TILE_SIZE; k++) {
            C_value += As[ty][k] * Bs[k][tx];
        }

        __syncthreads();
    }

    // Write back the result if within bounds
    if (row < N && col < N) {
        C[row * N + col] = C_value;
    }
}

