            float4 B_vec = reinterpret_cast<const float4*>(&B[B_row * N])[col / 4];
            Bs[ty][tx] = ((float*)&B_vec)[tx % 4];
        } else {
            Bs[ty][tx] = 0.0f;
        }

        __syncthreads();

        #pragma unroll 8
        for (int k = 0; k < TILE_SIZE; k += 4) {
            float4 a_vec, b_vec;

            a_vec.x = As[ty][k];
            a_vec.y = As[ty][k+1];
            a_vec.z = As[ty][k+2];
            a_vec.w = As[ty][k+3];

