            b_vec.y = Bs[k+1][tx];
            b_vec.z = Bs[k+2][tx];
            b_vec.w = Bs[k+3][tx];

            C_vec.x += a_vec.x * b_vec.x + a_vec.y * b_vec.y;
            C_vec.y += a_vec.z * b_vec.z + a_vec.w * b_vec.w;
        }

        __syncthreads();
    }

    if (row < N && col < N) {
        C[row * N + col] = C_vec.x + C_vec.y;
    }
}

