        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            C_value += As[curBuf][ty][k] * Bs[curBuf][k][tx];
        }

        // Swap buffers for next iteration
        curBuf = 1 - curBuf;
        nextBuf = 1 - nextBuf;

        __syncthreads();
    }

    // Process the last preloaded tile
    #pragma unroll
    for (int k = 0; k < TILE_SIZE; ++k) {
        C_value += As[curBuf][ty][k] * Bs[curBuf][k][tx];
    }

    C[row * N + col] = C_value;
