// CUDA kernel with loop unrolling for improved performance
__global__ void conv2d_relu_bias_kernel_unrolled(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C_out * H_out * W_out) {
        return;
    }

    // Decompose idx into (n, co, h_out, w_out)
    int w_out_idx = idx % W_out;
    int tmp       = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp           = tmp / H_out;
    int co        = tmp % C_out;
    int n         = tmp / C_out;

    // Start with convolution bias
    float val = conv_bias[co];

    // Loop over input channels
    for (int ci = 0; ci < C_in; ci++) {
        // Unroll the kernel height loop
        #pragma unroll
        for (int kh = 0; kh < K_h; kh++) {
            // Unroll the kernel width loop
            #pragma unroll
            for (int kw = 0; kw < K_w; kw++) {
                int x_h = h_out_idx + kh; // no padding, stride=1
                int x_w = w_out_idx + kw;
                float x_val = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
                float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
                val += x_val * w_val;
            }
        }
    }

    // Apply ReLU activation
    val = fmaxf(val, 0.0f);

    // Add the extra learnable bias
    val += bias[co];

    // Store the result
    out[idx] = val;
}

