#define NUM_STREAMS 4

__global__ void conv2d_relu_bias_kernel_streamed(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out,
    const int stream_offset,
    const int stream_elements) 
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= stream_elements) {
        return;
    }

    // Add offset to get global position
    idx += stream_offset;

    // Decompose idx into (n, co, h_out, w_out)
    int w_out_idx = idx % W_out;
    int tmp       = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp           = tmp / H_out;
    int co        = tmp % C_out;
    int n         = tmp / C_out;

    // Start with convolution bias
    float val = conv_bias[co];

    // Compute convolution
    for (int ci = 0; ci < C_in; ci++) {
        #pragma unroll
        for (int kh = 0; kh < K_h; kh++) {
            #pragma unroll
            for (int kw = 0; kw < K_w; kw++) {
                int x_h = h_out_idx + kh;
                int x_w = w_out_idx + kw;
