                float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
                val += x_val * w_val;
            }
        }
    }

    // ReLU activation
    val = fmaxf(val, 0.0f);

    // Add bias
    val += bias[co];

    // Store result
    out[idx] = val;
}

