    conv_weight = conv_weight.contiguous();
    conv_bias = conv_bias.contiguous();
    bias = bias.contiguous();

    auto out = torch::empty({N, C_out, H_out, W_out}, x.options());

    // Create CUDA streams
    cudaStream_t streams[NUM_STREAMS];
    for (int i = 0; i < NUM_STREAMS; i++) {
        cudaStreamCreate(&streams[i]);
    }

    const int total_elements = N * C_out * H_out * W_out;
    const int elements_per_stream = (total_elements + NUM_STREAMS - 1) / NUM_STREAMS;
    const int blockSize = 256;

    // Get raw pointers
    const float* x_ptr = x.data_ptr<float>();
    const float* weight_ptr = conv_weight.data_ptr<float>();
    const float* conv_bias_ptr = conv_bias.data_ptr<float>();
    const float* bias_ptr = bias.data_ptr<float>();
    float* out_ptr = out.data_ptr<float>();

    // Launch kernels in streams
    for (int i = 0; i < NUM_STREAMS; i++) {
        int stream_offset = i * elements_per_stream;
        int stream_elements = min(elements_per_stream, 
                                total_elements - stream_offset);

        if (stream_elements <= 0) continue;

        int gridSize = (stream_elements + blockSize - 1) / blockSize;

        conv2d_relu_bias_kernel_streamed<<<gridSize, blockSize, 0, streams[i]>>>(
            x_ptr,
            weight_ptr,
            conv_bias_ptr,
            bias_ptr,
            out_ptr,
