            C_in,
            H_in,
            W_in,
            C_out,
            K_h,
            K_w,
            H_out,
            W_out,
            stream_offset,
            stream_elements
        );
    }

    // Synchronize and destroy streams
    for (int i = 0; i < NUM_STREAMS; i++) {
        cudaStreamSynchronize(streams[i]);
        cudaStreamDestroy(streams[i]);
    }

    return out;
}

