// Define tile dimensions and subgroup size for partitioning the input channel summation
#define TILE_H 8
#define TILE_W 8
#define SUBGROUP 4

// Kernel: Each block computes a tile of output spatial positions for a given (n, co) pair.
// Multiple threads in a block collaborate to compute the convolution sum for each output pixel.
// Partial sums are accumulated in shared memory using atomicAdd, which confines atomic operations to shared memory only.
__global__ void tiled_atomic_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    // Determine the output spatial coordinate within the tile
    int out_w = blockIdx.x * TILE_W + threadIdx.x;  // Global output column
    int tile_row = threadIdx.y / SUBGROUP;            // Row index within the tile
    int subgroup_id = threadIdx.y % SUBGROUP;           // Index within subgroup for channel partitioning
    int out_h = blockIdx.y * TILE_H + tile_row;         // Global output row

    // Decode n and co from blockIdx.z. Grid dimension z covers N * C_out.
    int n = blockIdx.z / C_out;
    int co = blockIdx.z % C_out;

    // Check boundaries
    if (out_h >= H_out || out_w >= W_out) return;

    // Shared memory accumulator: one float per output pixel in the tile
    __shared__ float tile_accum[TILE_H * TILE_W];

    // Each output pixel in the tile is assigned a shared memory slot indexed by (tile_row * TILE_W + threadIdx.x).
    int tile_idx = tile_row * TILE_W + threadIdx.x;
    // Initialize the accumulator once per output pixel (only one thread per subgroup does initialization)
    if (subgroup_id == 0) {
        tile_accum[tile_idx] = 0.0f;
    }
    __syncthreads();

    float partial_sum = 0.0f;

    // Partition the summation over input channels among threads in the subgroup
    // Each thread starting at subgroup_id, stepping by SUBGROUP
    for (int ci = subgroup_id; ci < C_in; ci += SUBGROUP) {
        // Iterate over the kernel spatial dimensions
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                int in_h = out_h + kh;  // no padding, stride = 1
                int in_w = out_w + kw;
                int x_idx = ((n * C_in + ci) * H_in + in_h) * W_in + in_w;
                int w_idx = (((co * C_in + ci) * K_h + kh) * K_w + kw);
                partial_sum += x[x_idx] * conv_weight[w_idx];
            }
        }
    }

    // Atomically accumulate the partial sum into the shared memory accumulator for this output pixel
    atomicAdd(&tile_accum[tile_idx], partial_sum);
    __syncthreads();

    // One thread per output pixel (subgroup_id == 0) finalizes the result
    if (subgroup_id == 0) {
        float val = tile_accum[tile_idx] + conv_bias[co];
        val = fmaxf(val, 0.0f);  // Apply ReLU
        val += bias[co];
        int out_idx = ((n * C_out + co) * H_out + out_h) * W_out + out_w;
        out[out_idx] = val;
    }
}

