#include <algorithm>

__global__ void coalesced_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    // Calculate spatial position first to ensure coalesced memory access
    const int w_out_idx = blockIdx.x * blockDim.x + threadIdx.x;
    const int h_out_idx = blockIdx.y;
    const int co = blockIdx.z % C_out;
    const int n = blockIdx.z / C_out;

    if (w_out_idx >= W_out || h_out_idx >= H_out) {
        return;
    }

    // Pre-compute output index for coalesced writes
    const int out_idx = ((n * C_out + co) * H_out + h_out_idx) * W_out + w_out_idx;

    // Start with convolution bias
    float val = conv_bias[co];

    // Compute convolution with coalesced memory access
    #pragma unroll
    for (int ci = 0; ci < C_in; ci++) {
        #pragma unroll
        for (int kh = 0; kh < K_h; kh++) {
            const int h_in = h_out_idx + kh;
            #pragma unroll
            for (int kw = 0; kw < K_w; kw++) {
                const int w_in = w_out_idx + kw;

                // Coalesced read from input tensor
                const int x_idx = ((n * C_in + ci) * H_in + h_in) * W_in + w_in;
                const float x_val = x[x_idx];

                // Coalesced read from weight tensor
                const int w_idx = (((co * C_in) + ci) * K_h + kh) * K_w + kw;
                const float w_val = conv_weight[w_idx];

                val += x_val * w_val;
            }
        }
    }

    // ReLU activation
    val = fmaxf(val, 0.0f);

    // Add bias
    val += bias[co];

    // Coalesced write to output
    out[out_idx] = val;
}

