#define WARP_SIZE 32

__global__ void warp_aligned_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out,
    const int total_elements) {

    // Calculate aligned indices
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;
    const int warps_per_block = blockDim.x / WARP_SIZE;
    const int global_warp_id = blockIdx.x * warps_per_block + warp_id;

    // Each warp processes multiple elements in a coalesced manner
    const int elements_per_warp = WARP_SIZE;
    const int start_idx = global_warp_id * elements_per_warp + lane_id;

    // Pre-calculate stride constants
    const int w_stride = 1;
    const int h_stride = W_out;
    const int c_stride = H_out * W_out;
    const int n_stride = C_out * H_out * W_out;

    // Process multiple elements per thread if necessary
    #pragma unroll 1
    for (int idx = start_idx; idx < total_elements; idx += gridDim.x * blockDim.x) {
        // Bounds check moved outside of main computation
        if (idx < total_elements) {
            // Decompose index using pre-calculated strides
            const int w_out_idx = idx % W_out;
            const int h_out_idx = (idx / W_out) % H_out;
            const int co = (idx / (H_out * W_out)) % C_out;
            const int n = idx / (C_out * H_out * W_out);

            // Initialize accumulator with conv_bias
            float val = conv_bias[co];

            // Compute convolution with coalesced memory access pattern
            for (int ci = 0; ci < C_in; ci++) {
                const float* x_slice = &x[(n * C_in + ci) * H_in * W_in];
                const float* w_slice = &conv_weight[((co * C_in) + ci) * K_h * K_w];

                for (int kh = 0; kh < K_h; kh++) {
                    const int x_h = h_out_idx + kh;
                    for (int kw = 0; kw < K_w; kw++) {
                        const int x_w = w_out_idx + kw;
                        val += x_slice[x_h * W_in + x_w] * w_slice[kh * K_w + kw];
                    }
                }
            }

            // Branchless ReLU
            val = val * (val > 0.0f);

            // Add bias
            val += bias[co];

            // Store result
            out[idx] = val;
        }
    }
}

