// We divide the reduction dimension (over channels and kernel window) into NUM_GROUPS groups.
// This allows us to parallelize the reduction across multiple thread blocks per output pixel,
// and use atomicAdd in global memory only once per block to accumulate the partial sum.

#define NUM_GROUPS 8

// Kernel 1: Initialize the output array with the convolution bias for each output pixel.
__global__ void init_output_kernel(
    float* __restrict__ out,
    const float* __restrict__ conv_bias,
    const int total_outputs,
    const int C_out,
    const int W_out,
    const int H_out) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= total_outputs) return;

  // Decompose idx into (n, co, h, w)
  int w = idx % W_out;
  int tmp = idx / W_out;
  int h = tmp % H_out;
  tmp = tmp / H_out;
  int co = tmp % C_out;
  // n = tmp / C_out (not used further)
  out[idx] = conv_bias[co];
}

// Kernel 2: Accumulate convolution contributions using atomicAdd.
// The reduction dimension (over input channels and kernel elements) has size L = C_in * K_h * K_w.
// We split this reduction into NUM_GROUPS groups. Each block (identified by (output_idx, group_id))
// computes a partial sum over its assigned segment and then atomically adds it to the output pixel.
__global__ void accumulate_conv2d_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out,
    const int reduction_size) {

  // Each block works on one output pixel and one group of reduction indices.
  int output_idx = blockIdx.x;  // linear index for output pixel
  int group_id = blockIdx.y;      // which group this block processes
  int total_outputs = N * C_out * H_out * W_out;
  if (output_idx >= total_outputs) return;

  // Decompose output_idx into (n, co, h_out, w_out)
  int w_out = output_idx % W_out;
  int tmp = output_idx / W_out;
  int h_out = tmp % H_out;
  tmp = tmp / H_out;
  int co = tmp % C_out;
  int n = tmp / C_out;

  // Determine the segment (range) of the reduction dimension for this group
  int group_size = (reduction_size + NUM_GROUPS - 1) / NUM_GROUPS;
  int r_start = group_id * group_size;
  int r_end = min(r_start + group_size, reduction_size);

  float partial_sum = 0.0f;

  // Each thread processes a subset of indices in [r_start, r_end)
  for (int r = r_start + threadIdx.x; r < r_end; r += blockDim.x) {
    // Map r to (ci, kh, kw)
    int ci = r / (K_h * K_w);
    int rem = r % (K_h * K_w);
    int kh = rem / K_w;
    int kw = rem % K_w;

    int x_h = h_out + kh;  // no padding, stride=1
    int x_w = w_out + kw;
    float x_val = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
    float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
    partial_sum += x_val * w_val;
  }

  // Intra-block reduction in shared memory
  __shared__ float sdata[256];  // assume blockDim.x <= 256
  int tid = threadIdx.x;
  sdata[tid] = partial_sum;
  __syncthreads();

  // Reduce block's partial sums
  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) {
      sdata[tid] += sdata[tid + s];
    }
    __syncthreads();
  }

  // Thread 0 in the block performs atomicAdd to update global output
  if (tid == 0) {
    atomicAdd(&out[output_idx], sdata[0]);
  }
}

// Kernel 3: Finalize the output by applying ReLU and adding the extra bias.
__global__ void finalize_output_kernel(
    float* __restrict__ out,
    const float* __restrict__ bias,
    const int total_outputs,
    const int C_out,
    const int W_out,
    const int H_out) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= total_outputs) return;

  // Decompose idx to extract the channel index
  int w = idx % W_out;
  int tmp = idx / W_out;
  int h = tmp % H_out;
  tmp = tmp / H_out;
  int co = tmp % C_out;

  float val = out[idx];
  val = fmaxf(val, 0.0f);  // Apply ReLU activation
  val += bias[co];        // Add the extra learnable bias
  out[idx] = val;
}

// The forward function launches three consecutive kernels:
//  1. Initialization: set out = conv_bias for each output pixel.
//  2. Accumulation: accumulate convolution contributions from x and conv_weight using atomicAdd.
//  3. Finalization: apply ReLU and add the extra bias to produce the final result.

torch::Tensor conv2d_relu_bias_forward(
    torch::Tensor x,
    torch::Tensor conv_weight,
    torch::Tensor conv_bias,
    torch::Tensor bias) {
  TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
  TORCH_CHECK(conv_weight.is_cuda(), "conv_weight must be a CUDA tensor");
  TORCH_CHECK(conv_bias.is_cuda(), "conv_bias must be a CUDA tensor");
  TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
  TORCH_CHECK(x.dim() == 4, "x must have 4 dims (N, C_in, H_in, W_in)");
  TORCH_CHECK(conv_weight.dim() == 4, "conv_weight must have 4 dims (C_out, C_in, K_h, K_w)");
  TORCH_CHECK(conv_bias.dim() == 1, "conv_bias must have 1 dim (C_out)");
  TORCH_CHECK(bias.dim() == 1 || bias.dim() == 3, "bias must have shape (C_out) or (C_out, 1, 1)");

  int N = x.size(0);
  int C_in = x.size(1);
  int H_in = x.size(2);
  int W_in = x.size(3);
  int C_out = conv_weight.size(0);
  int K_h = conv_weight.size(2);
  int K_w = conv_weight.size(3);

  int H_out = H_in - K_h + 1;  // no padding, stride=1
  int W_out = W_in - K_w + 1;
  TORCH_CHECK(H_out > 0 && W_out > 0, "Invalid output dimensions");

  // Prepare output tensor with shape (N, C_out, H_out, W_out).
  auto out = torch::empty({N, C_out, H_out, W_out}, x.options());
  int total_outputs = N * C_out * H_out * W_out;

  // Kernel 1: Initialize output with conv_bias
  int blockSizeInit = 256;
  int gridSizeInit = (total_outputs + blockSizeInit - 1) / blockSizeInit;
  init_output_kernel<<<gridSizeInit, blockSizeInit>>>(
      out.data_ptr<float>(),
      conv_bias.data_ptr<float>(),
      total_outputs,
      C_out,
      W_out,
      H_out);

  // Compute reduction size over the input channels and spatial kernel window
  int reduction_size = C_in * K_h * K_w;
  // Kernel 2: Launch accumulation kernel with a 2D grid
  // grid.x dimension: each output pixel; grid.y dimension: NUM_GROUPS groups for reduction
  dim3 gridAcc(total_outputs, NUM_GROUPS);
  int blockSizeAcc = 256;
  accumulate_conv2d_kernel<<<gridAcc, blockSizeAcc>>>(
      x.data_ptr<float>(),
      conv_weight.data_ptr<float>(),
      out.data_ptr<float>(),
      N, C_in, H_in, W_in,
      C_out, K_h, K_w, H_out, W_out,
      reduction_size);

  // Kernel 3: Finalize output by applying ReLU and adding the extra bias
  int blockSizeFinal = 256;
  int gridSizeFinal = (total_outputs + blockSizeFinal - 1) / blockSizeFinal;
  finalize_output_kernel<<<gridSizeFinal, blockSizeFinal>>>(
      out.data_ptr<float>(),
      bias.data_ptr<float>(),
      total_outputs,
      C_out,
      W_out,
      H_out);

  return out;
}

