#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <vector>
#include <algorithm>

// Kernel that uses shared memory and warp-level primitives for reduction
__global__ void conv2d_relu_bias_kernel_shared(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    int N,
    int C_in,
    int H_in,
    int W_in,
    int C_out,
    int K_h,
    int K_w,
    int H_out,
    int W_out) {

    // Each block computes one output element
    int out_index = blockIdx.x;  // one block per output element

    // Decode out_index into (n, co, h_out, w_out)
    int w_out = out_index % W_out;
    int tmp = out_index / W_out;
    int h_out = tmp % H_out;
    tmp = tmp / H_out;
    int co = tmp % C_out;
    int n = tmp / C_out;

    // Total number of reduction iterations (over input channels and kernel positions)
    int reduction_size = C_in * K_h * K_w;
    float sum = 0.0f;

    // Each thread in the block computes a partial sum over a portion of the reduction
    for (int i = threadIdx.x; i < reduction_size; i += blockDim.x) {
        int ci = i / (K_h * K_w);
        int rem = i % (K_h * K_w);
        int kh = rem / K_w;
        int kw = rem % K_w;

        // Compute the index for the input tensor x
        int x_h = h_out + kh; // No padding, stride=1
        int x_w = w_out + kw;
        int x_index = ((n * C_in + ci) * H_in + x_h) * W_in + x_w;

        // Compute the index for the convolution weights
        int w_index = (((co * C_in + ci) * K_h + kh) * K_w + kw);

        sum += x[x_index] * conv_weight[w_index];
    }

    // Perform warp-level reduction using __shfl_down_sync
    unsigned int lane = threadIdx.x & 31;
    for (int offset = 16; offset > 0; offset /= 2) {
        sum += __shfl_down_sync(0xffffffff, sum, offset);
    }

    // Allocate shared memory for storing partial sums from each warp
    extern __shared__ float shared_sum[];
    int warp_id = threadIdx.x / 32;
    if (lane == 0) {
        shared_sum[warp_id] = sum;
    }
    __syncthreads();

    // Let the first warp reduce the partial sums from each warp
    float block_sum = 0.0f;
    if (threadIdx.x < (blockDim.x + 31) / 32) {
        block_sum = shared_sum[threadIdx.x];
    } else {
        block_sum = 0.0f;
    }

    // Use warp-level reduction for the final stage (assume at most 32 warps per block)
    for (int offset = 16; offset > 0; offset /= 2) {
        block_sum += __shfl_down_sync(0xffffffff, block_sum, offset);
    }

    // Thread 0 of the block writes the final result
    if (threadIdx.x == 0) {
        float final_val = conv_bias[co] + block_sum;
        final_val = fmaxf(final_val, 0.0f); // ReLU activation
        final_val += bias[co];
        out[out_index] = final_val;
    }
}

