// Kernel using a 3D grid to evenly distribute workload across threads and blocks
__global__ void conv2d_relu_bias_kernel_3d(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    // Each block in gridDim.z corresponds to a (n, co) pair
    int nc = blockIdx.z;  // overall index for (n, co)
    int n = nc / C_out;
    int co = nc % C_out;

    // Compute spatial output indices using 2D block and grid
    int out_x = blockIdx.x * blockDim.x + threadIdx.x;
    int out_y = blockIdx.y * blockDim.y + threadIdx.y;

    if (out_x < W_out && out_y < H_out) {
        // Compute the output index in tensor with shape (N, C_out, H_out, W_out)
        int out_index = ((n * C_out + co) * H_out + out_y) * W_out + out_x;

        // Start with convolution bias
        float val = conv_bias[co];

        // Accumulate over all input channels and the kernel window
        for (int ci = 0; ci < C_in; ci++) {
            for (int kh = 0; kh < K_h; kh++) {
                for (int kw = 0; kw < K_w; kw++) {
                    int in_y = out_y + kh;  // stride=1, no padding
                    int in_x = out_x + kw;
                    int x_index = ((n * C_in + ci) * H_in + in_y) * W_in + in_x;
                    int w_index = (((co * C_in + ci) * K_h + kh) * K_w) + kw;
                    val += x[x_index] * conv_weight[w_index];
                }
            }
        }

        // Apply ReLU activation
        val = fmaxf(val, 0.0f);
        // Add the extra learnable bias
        val += bias[co];

        // Write the result to the output tensor
        out[out_index] = val;
    }
}

