#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Kernel using shared memory for intra-block reduction and warp-level primitives for final reduction

// Each block computes one output element.
// Shared memory is used to accumulate the partial sums from each thread in the block.
// Then warp-level primitives (__shfl_down_sync) complete the final stage of reduction.

extern __shared__ float sdata[];

__global__ void conv2d_relu_bias_kernel_shared_reduction(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out)
{
    // Each block computes one output element
    int out_idx = blockIdx.x;
    int total_outputs = N * C_out * H_out * W_out;
    if (out_idx >= total_outputs) return;

    // Decode linear index into (n, co, h_out, w_out)
    int w = out_idx % W_out;
    int tmp = out_idx / W_out;
    int h = tmp % H_out;
    tmp = tmp / H_out;
    int co = tmp % C_out;
    int n = tmp / C_out;

    // Total number of multiplications for convolution (reduction size)
    int reduction_size = C_in * K_h * K_w;
    int tid = threadIdx.x;
    float partial_sum = 0.0f;

    // Each thread computes a part of the reduction
    for (int i = tid; i < reduction_size; i += blockDim.x) {
        int ci = i / (K_h * K_w);
        int rem = i % (K_h * K_w);
        int kh = rem / K_w;
        int kw = rem % K_w;

        // Compute indices into the input tensor and the conv weights
        int x_index = ((n * C_in + ci) * H_in + (h + kh)) * W_in + (w + kw);
        int w_index = (((co * C_in) + ci) * K_h + kh) * K_w + kw;

        partial_sum += x[x_index] * conv_weight[w_index];
    }

    // Store the partial sum in shared memory
    sdata[tid] = partial_sum;
    __syncthreads();

    // Intra-block reduction using shared memory
    // Reduce blockDim.x elements down to 32 elements
    for (unsigned int s = blockDim.x / 2; s > 32; s >>= 1) {
        if (tid < s) {
            sdata[tid] += sdata[tid + s];
        }
        __syncthreads();
    }

    // Final warp-level reduction
    if (tid < 32) {
        float val = sdata[tid];
        // Use warp shuffle to reduce within the warp
        for (int offset = 16; offset > 0; offset /= 2) {
            val += __shfl_down_sync(0xffffffff, val, offset);
        }
        if (tid == 0) {
            sdata[0] = val;  // final result stored in sdata[0]
        }
    }
    __syncthreads();

    // Thread 0 writes the result. Add convolution bias, apply ReLU, then add learnable bias.
    if (tid == 0) {
        float result = conv_bias[co] + sdata[0];
        result = fmaxf(result, 0.0f);
        result += bias[co];
        out[out_idx] = result;
    }
}

