#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <vector>
#include <algorithm>

// This kernel uses shared memory tiling to reduce global memory accesses.
// It loads a tile of the input for each input channel and reuses it for the convolution.
// The synchronization strategy has been optimized so that __syncthreads() is called only when necessary:
//   - One sync before loading new data (except for the first channel iteration) to ensure prior computation is finished.
//   - One sync after loading data into shared memory to ensure consistency before use.

__global__ void conv2d_relu_bias_kernel_shared_sync(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    // Determine sample index 'n' and output channel 'co' from blockIdx.z
    int n = blockIdx.z / C_out;
    int co = blockIdx.z % C_out;

    // Compute output coordinates for this thread
    int out_row = blockIdx.y * blockDim.y + threadIdx.y;
    int out_col = blockIdx.x * blockDim.x + threadIdx.x;

    // Base indices for the input tile in global memory
    int base_row = blockIdx.y * blockDim.y;
    int base_col = blockIdx.x * blockDim.x;

    // Shared memory tile dimensions (to cover the entire receptive field)
    int tile_w = blockDim.x + K_w - 1;
    int tile_h = blockDim.y + K_h - 1;
    int tile_size = tile_w * tile_h;

    // Declare dynamic shared memory
    extern __shared__ float shared_tile[];

    // Initialize accumulator with the convolution bias for this output channel
    float sum = conv_bias[co];

    // Loop over input channels
    for (int ci = 0; ci < C_in; ci++) {
        // For iterations after the first, synchronize to ensure previous compute is finished
        if (ci > 0) {
            __syncthreads();
        }

        // Each thread loads part of the input tile for channel 'ci' of sample 'n'
        // The tile covers the region needed to compute the corresponding output tile
        for (int idx = threadIdx.y * blockDim.x + threadIdx.x;
             idx < tile_size;
             idx += blockDim.x * blockDim.y) {
            int r = idx / tile_w;
            int c = idx % tile_w;
            int in_r = base_row + r;
            int in_c = base_col + c;
            float val = 0.0f;
            if (in_r < H_in && in_c < W_in) {
                int input_index = ((n * C_in + ci) * H_in + in_r) * W_in + in_c;
                val = x[input_index];
            }
            shared_tile[idx] = val;
        }
        // Synchronize to ensure the entire tile is loaded before computing
        __syncthreads();

        // Compute convolution for this input channel using the shared memory tile
        if (out_row < H_out && out_col < W_out) {
            for (int kh = 0; kh < K_h; kh++) {
                for (int kw = 0; kw < K_w; kw++) {
                    int s_row = threadIdx.y + kh;
                    int s_col = threadIdx.x + kw;
                    float x_val = shared_tile[s_row * tile_w + s_col];
                    int weight_index = (((co * C_in) + ci) * K_h + kh) * K_w + kw;
                    sum += x_val * conv_weight[weight_index];
                }
            }
        }
        // No extra __syncthreads() needed here as the next iteration will begin with one
    }

    // After accumulating over all input channels, apply ReLU and add the learnable bias
    if (out_row < H_out && out_col < W_out) {
        sum = fmaxf(sum, 0.0f);
        sum += bias[co];
        int out_index = ((n * C_out + co) * H_out + out_row) * W_out + out_col;
        out[out_index] = sum;
    }
}

// Wrapper function that prepares inputs and launches the CUDA kernel
torch::Tensor conv2d_relu_bias_forward(
    torch::Tensor x,
    torch::Tensor conv_weight,
    torch::Tensor conv_bias,
    torch::Tensor bias) {

    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(conv_weight.is_cuda(), "conv_weight must be a CUDA tensor");
    TORCH_CHECK(conv_bias.is_cuda(), "conv_bias must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(x.dim() == 4, "x must be of shape (N, C_in, H_in, W_in)");
    TORCH_CHECK(conv_weight.dim() == 4, "conv_weight must be of shape (C_out, C_in, K_h, K_w)");
    TORCH_CHECK(conv_bias.dim() == 1, "conv_bias must be of shape (C_out)");
    TORCH_CHECK(bias.dim() == 3 || bias.dim() == 1, "bias must be of shape (C_out, 1, 1) or (C_out,)");

    const int N = x.size(0);
    const int C_in = x.size(1);
    const int H_in = x.size(2);
    const int W_in = x.size(3);
    const int C_out = conv_weight.size(0);
    const int K_h = conv_weight.size(2);
    const int K_w = conv_weight.size(3);

    int H_out = H_in - K_h + 1;
    int W_out = W_in - K_w + 1;
    TORCH_CHECK(H_out > 0 && W_out > 0, "Invalid output dimensions");

    // Ensure inputs are contiguous
    x = x.contiguous();
    conv_weight = conv_weight.contiguous();
    conv_bias = conv_bias.contiguous();
    bias = bias.contiguous();

    auto out = torch::empty({N, C_out, H_out, W_out}, x.options());

    // Define block and grid dimensions
    // We use a 16x16 block for spatial dimensions; grid.z covers (N * C_out)
    dim3 block(16, 16);
    dim3 grid((W_out + block.x - 1) / block.x,
              (H_out + block.y - 1) / block.y,
              N * C_out);

    // Shared memory size: enough for a tile of size (block.x + K_w - 1) x (block.y + K_h - 1)
    int tile_w = block.x + K_w - 1;
    int tile_h = block.y + K_h - 1;
    size_t shared_mem_size = tile_w * tile_h * sizeof(float);

    const float* x_ptr = x.data_ptr<float>();
    const float* weight_ptr = conv_weight.data_ptr<float>();
    const float* conv_bias_ptr = conv_bias.data_ptr<float>();
    const float* bias_ptr = bias.data_ptr<float>();
    float* out_ptr = out.data_ptr<float>();

    conv2d_relu_bias_kernel_shared_sync<<<grid, block, shared_mem_size>>>(
        x_ptr,
        weight_ptr,
        conv_bias_ptr,
        bias_ptr,
        out_ptr,
        N, C_in, H_in, W_in,
        C_out, K_h, K_w,
        H_out, W_out
    );

    return out;
}

