// A CUDA kernel that computes 2D convolution followed by ReLU and a secondary bias add.
// This kernel is identical to the baseline kernel but will be launched on multiple CUDA streams
// to overlap computation with memory operations at a higher level.
__global__ void conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C_out * H_out * W_out) return;

    // Decompose idx into (n, co, h_out, w_out)
    int w_out_idx = idx % W_out;
    int tmp       = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp           = tmp / H_out;
    int co        = tmp % C_out;
    int n         = tmp / C_out;

    // Start with the convolution bias
    float val = conv_bias[co];

    // Accumulate convolution result
    for (int ci = 0; ci < C_in; ci++) {
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                int x_h = h_out_idx + kh;  // no padding, stride=1
                int x_w = w_out_idx + kw;
                float x_val = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
                float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
                val += x_val * w_val;
            }
        }
    }

    // ReLU activation
    val = fmaxf(val, 0.0f);

    // Add the extra learnable bias
    val += bias[co];

    // Store the result
    out[idx] = val;
}

// New forward function that partitions the batch dimension and launches kernels on multiple CUDA streams
// to overlap computation with memory operations (e.g., asynchronous kernel launches, potential overlapping
// of memory transfer if data is streamed in/out).

torch::Tensor conv2d_relu_bias_forward(
    torch::Tensor x,
    torch::Tensor conv_weight,
    torch::Tensor conv_bias,
    torch::Tensor bias) {

    // Ensure inputs are CUDA tensors and have valid dimensions
    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(conv_weight.is_cuda(), "conv_weight must be a CUDA tensor");
    TORCH_CHECK(conv_bias.is_cuda(), "conv_bias must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(x.dim() == 4, "x must be of shape (N, C_in, H_in, W_in)");
    TORCH_CHECK(conv_weight.dim() == 4, "conv_weight must be of shape (C_out, C_in, K_h, K_w)");
    TORCH_CHECK(conv_bias.dim() == 1, "conv_bias must be of shape (C_out)");
    TORCH_CHECK(bias.dim() == 3 || bias.dim() == 1, "bias must be of shape (C_out, 1, 1) or (C_out)");

    const auto N     = x.size(0);
    const auto C_in  = x.size(1);
    const auto H_in  = x.size(2);
    const auto W_in  = x.size(3);
    const auto C_out = conv_weight.size(0);
    const auto K_h   = conv_weight.size(2);
    const auto K_w   = conv_weight.size(3);

    auto H_out = H_in - K_h + 1;  // default stride=1, no padding
    auto W_out = W_in - K_w + 1;
    TORCH_CHECK(H_out > 0 && W_out > 0, "Output size (H_out, W_out) must be positive. Check kernel size vs input.");

    // Make tensors contiguous
    x            = x.contiguous();
    conv_weight  = conv_weight.contiguous();
    conv_bias    = conv_bias.contiguous();
    bias         = bias.contiguous();

    // Prepare output tensor
    auto out = torch::empty({N, C_out, H_out, W_out}, x.options());

    const int blockSize = 256;
    // Determine number of streams. Here we choose up to 4 streams or fewer if batch size (N) is smaller.
    int num_streams = std::min((int)N, 4);
    int chunk_size = (N + num_streams - 1) / num_streams;

    // Create CUDA streams
    std::vector<cudaStream_t> streams(num_streams);
    for (int i = 0; i < num_streams; i++) {
        cudaStreamCreate(&streams[i]);
    }

    const float* x_ptr          = x.data_ptr<float>();
    const float* weight_ptr     = conv_weight.data_ptr<float>();
    const float* conv_bias_ptr  = conv_bias.data_ptr<float>();
    const float* bias_ptr       = bias.data_ptr<float>();
    float* out_ptr              = out.data_ptr<float>();

    // For each stream, launch the kernel on a partition of the batch dimension
    for (int i = 0; i < num_streams; i++) {
        int start_n = i * chunk_size;
        if (start_n >= N) break;  // no more samples to process
        int current_chunk = std::min(chunk_size, (int)N - start_n);
        int total_threads_chunk = current_chunk * C_out * H_out * W_out;
        int gridSize = (total_threads_chunk + blockSize - 1) / blockSize;

        // Offset the input and output pointers by the batch dimension
        const float* x_chunk_ptr = x_ptr + start_n * C_in * H_in * W_in;
        float* out_chunk_ptr = out_ptr + start_n * C_out * H_out * W_out;

        conv2d_relu_bias_kernel<<<gridSize, blockSize, 0, streams[i]>>>(
            x_chunk_ptr,
            weight_ptr,
            conv_bias_ptr,
            bias_ptr,
            out_chunk_ptr,
            current_chunk,
            C_in,
            H_in,
            W_in,
            C_out,
            K_h,
            K_w,
            H_out,
            W_out
        );
    }

    // Synchronize and destroy streams
    for (int i = 0; i < num_streams; i++) {
        cudaStreamSynchronize(streams[i]);
        cudaStreamDestroy(streams[i]);
    }

    return out;
}

