    const int K_w,
    const int H_out,
    const int W_out) {

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= sub_N * C_out * H_out * W_out) return;

    // Decompose idx into (n, co, h_out, w_out) for the current sub-batch
    int w_out_idx = idx % W_out;
    int tmp       = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp           = tmp / H_out;
    int co        = tmp % C_out;
    int n         = tmp / C_out;  // local batch index within the sub-batch

    // Start with convolution bias
    float val = conv_bias[co];

    // Perform convolution over the input channels and kernel spatial dimensions
    for (int ci = 0; ci < C_in; ci++) {
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                int x_h = h_out_idx + kh;  // no padding, stride=1
                int x_w = w_out_idx + kw;
                float x_val = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
                float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
                val += x_val * w_val;
            }
        }
    }

    // Apply ReLU activation
    val = fmaxf(val, 0.0f);

    // Add extra learnable bias
    val += bias[co];

    // Write the result
    out[idx] = val;
}

// This function partitions the batch dimension and uses multiple CUDA streams to overlap
// kernel execution with (potential) memory operations. This can help hide memory latency
// by pipelining different sub-batch computations concurrently on the GPU.

torch::Tensor streamed_conv2d_relu_bias_forward(
    torch::Tensor x,
    torch::Tensor conv_weight,
    torch::Tensor conv_bias,
    torch::Tensor bias) {

    // Check that all tensors are CUDA tensors and have the expected dimensionality
    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(conv_weight.is_cuda(), "conv_weight must be a CUDA tensor");
    TORCH_CHECK(conv_bias.is_cuda(), "conv_bias must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(x.dim() == 4, "x must be of shape (N, C_in, H_in, W_in)");
    TORCH_CHECK(conv_weight.dim() == 4, "conv_weight must be of shape (C_out, C_in, K_h, K_w)");
    TORCH_CHECK(conv_bias.dim() == 1, "conv_bias must be of shape (C_out)");
    TORCH_CHECK(bias.dim() == 3 || bias.dim() == 1, "bias must be of shape (C_out, 1, 1) or (C_out)");

    const int N     = x.size(0);
    const int C_in  = x.size(1);
    const int H_in  = x.size(2);
    const int W_in  = x.size(3);
    const int C_out = conv_weight.size(0);
    const int K_h   = conv_weight.size(2);
    const int K_w   = conv_weight.size(3);

    // Compute output dimensions (assuming stride=1 and no padding)
    const int H_out = H_in - K_h + 1;
    const int W_out = W_in - K_w + 1;
    TORCH_CHECK(H_out > 0 && W_out > 0, "Output size (H_out, W_out) must be positive. Check kernel size vs input.");

    // Ensure tensors are contiguous
    x            = x.contiguous();
    conv_weight  = conv_weight.contiguous();
    conv_bias    = conv_bias.contiguous();
    bias         = bias.contiguous();

    // Prepare output tensor
    auto out = torch::empty({N, C_out, H_out, W_out}, x.options());

    // Define kernel launch parameters
    const int blockSize = 256;
    // Define the number of streams to use for overlapping execution
    const int num_streams = 4;  // Can be tuned based on workload and device
    int chunk_size = (N + num_streams - 1) / num_streams; // Number of images per stream

    // Create CUDA streams
    std::vector<cudaStream_t> streams(num_streams);
    for (int i = 0; i < num_streams; ++i) {
        cudaStreamCreate(&streams[i]);
    }

    // Get raw pointers to data
    const float* x_ptr         = x.data_ptr<float>();
    const float* weight_ptr    = conv_weight.data_ptr<float>();
    const float* conv_bias_ptr = conv_bias.data_ptr<float>();
    const float* bias_ptr      = bias.data_ptr<float>();
    float* out_ptr             = out.data_ptr<float>();

    // Partition the batch dimension and launch asynchronous kernels on each stream
    for (int i = 0; i < num_streams; i++) {
        int n_start = i * chunk_size;
        if (n_start >= N) break;  // No more data
        int current_chunk = std::min(chunk_size, N - n_start);

        int total_threads = current_chunk * C_out * H_out * W_out;
        int gridSize = (total_threads + blockSize - 1) / blockSize;

        // Offset pointers for the current sub-batch
        const float* x_chunk_ptr = x_ptr + n_start * C_in * H_in * W_in;
        float* out_chunk_ptr = out_ptr + n_start * C_out * H_out * W_out;

        // Launch the kernel asynchronously on the designated stream
        conv2d_relu_bias_kernel<<<gridSize, blockSize, 0, streams[i]>>>(
            x_chunk_ptr,
            weight_ptr,
            conv_bias_ptr,
            bias_ptr,
            out_chunk_ptr,
            current_chunk,
            C_in,
            H_in,
            W_in,
            C_out,
            K_h,
            K_w,
            H_out,
            W_out
        );
    }

    // Synchronize and destroy streams to ensure all work is completed
    for (auto s : streams) {
        cudaStreamSynchronize(s);
        cudaStreamDestroy(s);
    }

    return out;
}

