#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <vector>
#include <algorithm>
#include <cmath>

// Optimized kernel: each block computes one output element by splitting the inner
// convolution sum (over C_in, K_h, K_w) among its threads. Partial sums are reduced in
// shared memory, thereby avoiding global atomic operations and reducing contention.
__global__ void conv2d_relu_bias_kernel_optimized(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out)
{
    // Each block computes one output element: out[n, co, h, w]
    int out_index = blockIdx.x;
    if (out_index >= N * C_out * H_out * W_out) return;

    // Decompose out_index into (n, co, h, w)
    int w = out_index % W_out;
    int tmp = out_index / W_out;
    int h = tmp % H_out;
    tmp = tmp / H_out;
    int co = tmp % C_out;
    int n = tmp / C_out;

    // Total number of inner-loop iterations: over input channels and kernel spatial dims
    int total_inner = C_in * K_h * K_w;

    float partial_sum = 0.0f;

    // Each thread in the block computes a partial sum over a slice of the inner loop
    for (int i = threadIdx.x; i < total_inner; i += blockDim.x) {
        int ci = i / (K_h * K_w);
        int rem = i % (K_h * K_w);
        int kh = rem / K_w;
        int kw = rem % K_w;

        int x_h = h + kh;  // no padding, stride=1
        int x_w = w + kw;
        float x_val = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
        float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
        partial_sum += x_val * w_val;
    }

    // Use shared memory for block-level reduction of partial sums
    extern __shared__ float sdata[];
    sdata[threadIdx.x] = partial_sum;
    __syncthreads();

    // In-place reduction in shared memory
    for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (threadIdx.x < s) {
            sdata[threadIdx.x] += sdata[threadIdx.x + s];
        }
        __syncthreads();
    }

    // Thread 0 applies the activation and adds the biases, then writes to global memory
    if (threadIdx.x == 0) {
        float val = conv_bias[co] + sdata[0];
        val = fmaxf(val, 0.0f);  // ReLU activation
        val += bias[co];
        out[out_index] = val;
    }
}

