// Optimized CUDA kernel using shared memory and warp-level primitives
__global__ void conv2d_relu_bias_shared_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out)
{
    extern __shared__ float shared_mem[];
    int tid = threadIdx.x;
    int block_offset = blockIdx.x * blockDim.x;
    int idx = block_offset + tid;

    if (idx >= N * C_out * H_out * W_out) {
        return;
    }

    int w_out_idx = idx % W_out;
    int tmp       = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp           = tmp / H_out;
    int co        = tmp % C_out;
    int n         = tmp / C_out;

    float val = conv_bias[co];

    for (int ci = 0; ci < C_in; ci++) {
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                int x_h = h_out_idx + kh;
                int x_w = w_out_idx + kw;
                float x_val = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
                float w_val = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
                val += x_val * w_val;
            }
        }
    }

    val = fmaxf(val, 0.0f);
    val += bias[co];

    shared_mem[tid] = val;
    __syncthreads();

    for (int offset = blockDim.x / 2; offset > 0; offset >>= 1) {
        if (tid < offset) {
            shared_mem[tid] += shared_mem[tid + offset];
        }
        __syncthreads();
    }

    if (tid == 0) {
        out[block_offset] = shared_mem[0];
    }
}

