#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <vector>
#include <algorithm>

// Define shared memory tile sizes
#define TILE_SIZE 16
#define KERNEL_TILE 3

__global__ void shared_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    __shared__ float s_input[TILE_SIZE][TILE_SIZE];
    __shared__ float s_weight[KERNEL_TILE][KERNEL_TILE];

    const int tx = threadIdx.x;
    const int ty = threadIdx.y;
    const int bx = blockIdx.x;
    const int by = blockIdx.y;
    const int bz = blockIdx.z;

    const int h_out_start = by * TILE_SIZE + ty;
    const int w_out_start = bx * TILE_SIZE + tx;

    if (h_out_start >= H_out || w_out_start >= W_out) return;

    const int n = bz / C_out;
    const int co = bz % C_out;

    float accumulator = conv_bias[co];

    // Loop over input channels
    for (int ci = 0; ci < C_in; ci++) {
        // Load input tile into shared memory
        for (int i = ty; i < TILE_SIZE + K_h - 1; i += blockDim.y) {
            for (int j = tx; j < TILE_SIZE + K_w - 1; j += blockDim.x) {
                const int h_in = by * TILE_SIZE + i;
                const int w_in = bx * TILE_SIZE + j;
                if (h_in < H_in && w_in < W_in) {
                    s_input[i][j] = x[((n * C_in + ci) * H_in + h_in) * W_in + w_in];
                } else {
                    s_input[i][j] = 0.0f;
                }
            }
        }

        // Load weight tile into shared memory
        if (ty < K_h && tx < K_w) {
            s_weight[ty][tx] = conv_weight[(((co * C_in) + ci) * K_h + ty) * K_w + tx];
        }

        __syncthreads();

        // Compute convolution for this input channel
        if (h_out_start < H_out && w_out_start < W_out) {
            for (int kh = 0; kh < K_h; kh++) {
                for (int kw = 0; kw < K_w; kw++) {
                    accumulator += s_input[ty + kh][tx + kw] * s_weight[kh][kw];
                }
            }
        }

        __syncthreads();
    }

    // Apply ReLU and add bias
    if (h_out_start < H_out && w_out_start < W_out) {
        accumulator = fmaxf(accumulator, 0.0f);
        accumulator += bias[co];

        // Store result
        out[((n * C_out + co) * H_out + h_out_start) * W_out + w_out_start] = accumulator;
    }
}

torch::Tensor conv2d_relu_bias_forward(
    torch::Tensor x,
    torch::Tensor conv_weight,
    torch::Tensor conv_bias,
    torch::Tensor bias) {

    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(conv_weight.is_cuda(), "conv_weight must be a CUDA tensor");
    TORCH_CHECK(conv_bias.is_cuda(), "conv_bias must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");

    const int N = x.size(0);
    const int C_in = x.size(1);
    const int H_in = x.size(2);
    const int W_in = x.size(3);
    const int C_out = conv_weight.size(0);
    const int K_h = conv_weight.size(2);
    const int K_w = conv_weight.size(3);

    const int H_out = H_in - K_h + 1;
    const int W_out = W_in - K_w + 1;

    // Make tensors contiguous
    x = x.contiguous();
    conv_weight = conv_weight.contiguous();
    conv_bias = conv_bias.contiguous();
    bias = bias.contiguous();

    auto out = torch::empty({N, C_out, H_out, W_out}, x.options());

    // Set up grid and block dimensions
    dim3 threads(TILE_SIZE, TILE_SIZE);
    dim3 grid(
        (W_out + TILE_SIZE - 1) / TILE_SIZE,
        (H_out + TILE_SIZE - 1) / TILE_SIZE,
        N * C_out
    );

    shared_conv2d_relu_bias_kernel<<<grid, threads>>>(
        x.data_ptr<float>(),
        conv_weight.data_ptr<float>(),
        conv_bias.data_ptr<float>(),
        bias.data_ptr<float>(),
        out.data_ptr<float>(),
        N, C_in, H_in, W_in,
        C_out, K_h, K_w,
        H_out, W_out
    );

    return out;
}

