#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <vector>
#include <algorithm>

// Shared memory tile sizes
#define TILE_WIDTH 16
#define WARP_SIZE 32

__global__ void shared_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    __shared__ float shared_x[TILE_WIDTH][TILE_WIDTH];
    __shared__ float shared_weight[TILE_WIDTH][TILE_WIDTH];

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C_out * H_out * W_out) return;

    // Decompose idx into (n, co, h_out, w_out)
    int w_out_idx = idx % W_out;
    int tmp = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp = tmp / H_out;
    int co = tmp % C_out;
    int n = tmp / C_out;

    // Initialize accumulator with conv_bias
    float val = conv_bias[co];

    // Calculate lane ID within warp
    const unsigned int lane_id = threadIdx.x % WARP_SIZE;

    // Process input channels in tiles
    for (int ci = 0; ci < C_in; ci++) {
        float partial_sum = 0.0f;

        // Load input and weight data into shared memory tiles
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                if (threadIdx.x < K_h * K_w) {
                    int x_h = h_out_idx + kh;
                    int x_w = w_out_idx + kw;
                    if (x_h < H_in && x_w < W_in) {
                        shared_x[kh][kw] = x[((n * C_in + ci) * H_in + x_h) * W_in + x_w];
                        shared_weight[kh][kw] = conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
                    }
                }
            }
        }
        __syncthreads();

        // Compute partial convolution
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                partial_sum += shared_x[kh][kw] * shared_weight[kh][kw];
            }
        }

        // Warp-level reduction using shuffle operations
        #pragma unroll
        for (int offset = WARP_SIZE/2; offset > 0; offset /= 2) {
            partial_sum += __shfl_down_sync(0xffffffff, partial_sum, offset);
        }

        // First thread in warp accumulates the result
        if (lane_id == 0) {
            val += partial_sum;
        }

        __syncthreads();
    }

    // Only the first thread in each warp writes the result
    if (lane_id == 0) {
        // Apply ReLU
        val = fmaxf(val, 0.0f);
        // Add bias
        val += bias[co];
        // Store result
        out[idx] = val;
    }
}

