// Device function for loading input tile into shared memory
__device__ void load_input_tile(
    const float* __restrict__ x,
    float* __restrict__ shared_input,
    int n, int ci, int h_start, int w_start,
    int H_in, int W_in, int tile_size, int C_in) {

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    for (int i = tid; i < tile_size * tile_size; i += block_size) {
        int h_offset = i / tile_size;
        int w_offset = i % tile_size;
        int h_pos = h_start + h_offset;
        int w_pos = w_start + w_offset;

        if (h_pos < H_in && w_pos < W_in) {
            shared_input[h_offset * tile_size + w_offset] = 
                x[((n * C_in + ci) * H_in + h_pos) * W_in + w_pos];
        } else {
            shared_input[h_offset * tile_size + w_offset] = 0.0f;
        }
    }
}

// Device function for loading weight tile into shared memory
__device__ void load_weight_tile(
    const float* __restrict__ conv_weight,
    float* __restrict__ shared_weight,
    int co, int ci, int K_h, int K_w, int C_in) {

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    for (int i = tid; i < K_h * K_w; i += block_size) {
        int kh = i / K_w;
        int kw = i % K_w;
        shared_weight[kh * K_w + kw] = 
            conv_weight[(((co * C_in) + ci) * K_h + kh) * K_w + kw];
    }
}

// Device function for convolution computation
__device__ float compute_conv(
    const float* __restrict__ shared_input,
    const float* __restrict__ shared_weight,
    int h_local, int w_local,
    int K_h, int K_w,
    int tile_size) {

    float sum = 0.0f;
    #pragma unroll
    for (int kh = 0; kh < K_h; kh++) {
        #pragma unroll
        for (int kw = 0; kw < K_w; kw++) {
            sum += shared_input[(h_local + kh) * tile_size + (w_local + kw)] *
                   shared_weight[kh * K_w + kw];
        }
    }
    return sum;
}

__global__ void shared_memory_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N, const int C_in, const int H_in, const int W_in,
    const int C_out, const int K_h, const int K_w,
    const int H_out, const int W_out,
    const int TILE_SIZE) {

    extern __shared__ float shared_mem[];
    float* shared_input = shared_mem;
    float* shared_weight = &shared_mem[TILE_SIZE * TILE_SIZE];

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C_out * H_out * W_out) return;

    int w_out_idx = idx % W_out;
    int tmp = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp = tmp / H_out;
    int co = tmp % C_out;
    int n = tmp / C_out;

    float val = conv_bias[co];

    for (int ci = 0; ci < C_in; ci++) {
        int h_start = h_out_idx;
        int w_start = w_out_idx;

        load_input_tile(x, shared_input, n, ci, h_start, w_start,
                       H_in, W_in, TILE_SIZE, C_in);

        load_weight_tile(conv_weight, shared_weight, co, ci, K_h, K_w, C_in);

        __syncthreads();

        val += compute_conv(shared_input, shared_weight,
                          h_out_idx - h_start, w_out_idx - w_start,
                          K_h, K_w, TILE_SIZE);

        __syncthreads();
    }

    val = fmaxf(val, 0.0f);
    val += bias[co];
    out[idx] = val;
}

