// Device function for convolution operation
__device__ float conv2d(float* x, float* kernel, int C_in, int K_h, int K_w, int x_h, int x_w, int H_in, int W_in) {
    float sum = 0.0f;
    for (int ci = 0; ci < C_in; ci++) {
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                sum += x[(ci * H_in + (x_h + kh)) * W_in + (x_w + kw)] *
                       kernel[(ci * K_h + kh) * K_w + kw];
            }
        }
    }
    return sum;
}

__global__ void optimized_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out)
{
    // Global thread index
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * C_out * H_out * W_out) {
        return;
    }

    // Decompose idx into (n, co, h_out, w_out)
    int w_out_idx = idx % W_out;
    int tmp       = idx / W_out;
    int h_out_idx = tmp % H_out;
    tmp           = tmp / H_out;
    int co        = tmp % C_out;
    int n         = tmp / C_out;

    // Aggregate bias with the convolution operation
    float val = conv_bias[co] + conv2d(x + ((n * C_in) * H_in * W_in), 
                                       conv_weight + (co * C_in * K_h * K_w),
                                       C_in, K_h, K_w, h_out_idx, w_out_idx, H_in, W_in);

    // ReLU activation
    val = fmaxf(val, 0.0f);

    // Add the extra learnable bias
    val += bias[co];

    // Store the result
    out[idx] = val;
}

