#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

// Define tile dimensions and warp size
#define TILE_H 8
#define TILE_W 8
#define WARP_SIZE 32

// This kernel assigns one warp per output pixel. The warp collaboratively sums the partial contributions
// over the input channels and the kernel window using warp shuffle reductions. This approach eliminates
// costly shared memory atomics and leverages fast register and intra-warp communication.
__global__ void warp_tiled_conv2d_relu_bias_kernel(
    const float* __restrict__ x,
    const float* __restrict__ conv_weight,
    const float* __restrict__ conv_bias,
    const float* __restrict__ bias,
    float* __restrict__ out,
    const int N,
    const int C_in,
    const int H_in,
    const int W_in,
    const int C_out,
    const int K_h,
    const int K_w,
    const int H_out,
    const int W_out) {

    // Each block processes a tile of output spatial positions for a given (n, co) pair.
    // Decode n and co from blockIdx.z.
    int n  = blockIdx.z / C_out;
    int co = blockIdx.z % C_out;

    // Each block is organized so that one warp computes one output pixel in the tile.
    // Block dimensions: blockDim.x = TILE_W, blockDim.y = TILE_H * WARP_SIZE.
    // warpId: which tile row (0 to TILE_H-1)
    // laneId: within warp (0 to WARP_SIZE-1) which will partition the input channel summation
    int warpId = threadIdx.y / WARP_SIZE;  // tile row
    int laneId = threadIdx.y % WARP_SIZE;   // lane inside the warp
    int tile_col = threadIdx.x;             // tile column index

    // Compute global (out_h, out_w) for this output pixel
    int out_h = blockIdx.y * TILE_H + warpId;
    int out_w = blockIdx.x * TILE_W + tile_col;
    if (out_h >= H_out || out_w >= W_out) return;

    // Each thread in the warp will compute a partial sum over a subset of the input channels and kernel window
    float sum = 0.0f;

    // Partition the summation over the input channels using the laneId stride
    for (int ci = laneId; ci < C_in; ci += WARP_SIZE) {
        for (int kh = 0; kh < K_h; kh++) {
            for (int kw = 0; kw < K_w; kw++) {
                int in_h = out_h + kh;  // No padding, stride=1
                int in_w = out_w + kw;
                // Compute the index for input tensor: (n, ci, in_h, in_w)
                int x_idx = ((n * C_in + ci) * H_in + in_h) * W_in + in_w;
                // Compute the index for weight tensor: (co, ci, kh, kw)
                int w_idx = (((co * C_in + ci) * K_h) + kh) * K_w + kw;
                sum += x[x_idx] * conv_weight[w_idx];
            }
        }
    }

    // Use warp-level reduction to sum up the partial sums from all lanes
    // __shfl_down_sync synchronizes within the warp
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        sum += __shfl_down_sync(0xffffffff, sum, offset);
    }

    // The first lane of each warp finalizes the output computation
    if (laneId == 0) {
        float val = sum + conv_bias[co];
        // Apply ReLU activation
        val = fmaxf(val, 0.0f);
        // Add extra learnable bias
        val += bias[co];
        // Compute the output index: (n, co, out_h, out_w)
        int out_idx = ((n * C_out + co) * H_out + out_h) * W_out + out_w;
        out[out_idx] = val;
    }
}

// Wrapper function accessible from PyTorch
// x:          (N, C_in, H_in, W_in)
// conv_weight:(C_out, C_in, K_h, K_w)
// conv_bias:  (C_out)
// bias:       (C_out, 1, 1)  or (C_out,)

torch::Tensor warp_tiled_conv2d_relu_bias_forward(
    torch::Tensor x,
    torch::Tensor conv_weight,
    torch::Tensor conv_bias,
    torch::Tensor bias) {
    // Ensure the input tensors are CUDA tensors and have the expected dimensions
    TORCH_CHECK(x.is_cuda(), "x must be a CUDA tensor");
    TORCH_CHECK(conv_weight.is_cuda(), "conv_weight must be a CUDA tensor");
    TORCH_CHECK(conv_bias.is_cuda(), "conv_bias must be a CUDA tensor");
    TORCH_CHECK(bias.is_cuda(), "bias must be a CUDA tensor");
    TORCH_CHECK(x.dim() == 4, "x must be of shape (N, C_in, H_in, W_in)");
    TORCH_CHECK(conv_weight.dim() == 4, "conv_weight must be of shape (C_out, C_in, K_h, K_w)");
    TORCH_CHECK(conv_bias.dim() == 1, "conv_bias must be of shape (C_out)");
    TORCH_CHECK(bias.dim() == 3 || bias.dim() == 1, "bias must be of shape (C_out, 1, 1) or (C_out,)");

    const int N     = x.size(0);
    const int C_in  = x.size(1);
    const int H_in  = x.size(2);
    const int W_in  = x.size(3);
    const int C_out = conv_weight.size(0);
    const int K_h   = conv_weight.size(2);
    const int K_w   = conv_weight.size(3);

    const int H_out = H_in - K_h + 1; // no padding, stride=1
    const int W_out = W_in - K_w + 1;
    TORCH_CHECK(H_out > 0 && W_out > 0, "Invalid output dimensions: check kernel size vs input size");

    // Make sure tensors are contiguous
    x            = x.contiguous();
    conv_weight  = conv_weight.contiguous();
    conv_bias    = conv_bias.contiguous();
    bias         = bias.contiguous();

    auto out = torch::empty({N, C_out, H_out, W_out}, x.options());

    // Setup block dimensions:
    // Each block covers a tile of output pixels for a given (n, co) pair.
    // blockDim.x = TILE_W, blockDim.y = TILE_H * WARP_SIZE
    dim3 blockDim(TILE_W, TILE_H * WARP_SIZE);
    // Grid dimensions: gridDim.x and gridDim.y cover the output spatial dimensions,
    // gridDim.z covers all (n, co) pairs
    dim3 gridDim((W_out + TILE_W - 1) / TILE_W,
                 (H_out + TILE_H - 1) / TILE_H,
                 N * C_out);

    const float* x_ptr         = x.data_ptr<float>();
    const float* weight_ptr    = conv_weight.data_ptr<float>();
    const float* conv_bias_ptr = conv_bias.data_ptr<float>();
    const float* bias_ptr      = bias.data_ptr<float>();
    float* out_ptr             = out.data_ptr<float>();

    warp_tiled_conv2d_relu_bias_kernel<<<gridDim, blockDim>>>(
        x_ptr,
        weight_ptr,
        conv_bias_ptr,
        bias_ptr,
        out_ptr,
        N, C_in, H_in, W_in,
        C_out, K_h, K_w,
        H_out, W_out);

    return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("forward", &warp_tiled_conv2d_relu_bias_forward, "Optimized forward pass for 2D convolution + ReLU + bias using warp-level tiling");
}

#include <torch/extension.h>
#include <vector>

// Define tile size for shared memory blocking
#define TILE_SIZE 16

// Kernel for a single linear (dense) layer with optional ReLU activation.
// Computes: output[i, j] = dot(input[i, :], weight[j, :]) + bias[j]
// where input is of size [batch_size, in_features] and weight is of size [out_features, in_features].
// Note: We compute x * weight^T, since PyTorch's linear layer uses weight of shape [out_features, in_features].

__global__ void mlp_layer_kernel(const float* __restrict__ input,
                                 const float* __restrict__ weight,
                                 const float* __restrict__ bias,
                                 float* output,
                                 int batch_size,
                                 int in_features,
                                 int out_features,
                                 bool apply_relu) {
  // Shared memory for tiles of input and transposed weight data
  __shared__ float tile_A[TILE_SIZE][TILE_SIZE];
  __shared__ float tile_B[TILE_SIZE][TILE_SIZE];

  // Calculate the row (batch index) and column (output neuron index)
  int row = blockIdx.y * TILE_SIZE + threadIdx.y;
  int col = blockIdx.x * TILE_SIZE + threadIdx.x;

  float sum = 0.0f;

  // Number of tiles to cover the full in_features dimension
  int numTiles = (in_features + TILE_SIZE - 1) / TILE_SIZE;

  // Loop over tiles
  for (int tile = 0; tile < numTiles; ++tile) {
    // Load a tile of the input matrix from global memory
    int input_col = tile * TILE_SIZE + threadIdx.x;
    if (row < batch_size && input_col < in_features) {
      tile_A[threadIdx.y][threadIdx.x] = input[row * in_features + input_col];
    } else {
      tile_A[threadIdx.y][threadIdx.x] = 0.0f;
    }

    // Load a tile of the weight matrix (transposed on the fly).
    // Our weight matrix is of shape [out_features, in_features]. To compute
    // output = input * weight^T, we require elements: weight[col, k] for k in the tile.
    int weight_k = tile * TILE_SIZE + threadIdx.y;  // index in the in_features dimension
    if (col < out_features && weight_k < in_features) {
      // weight is stored in row-major order as [out_features, in_features]
      tile_B[threadIdx.y][threadIdx.x] = weight[col * in_features + weight_k];
    } else {
      tile_B[threadIdx.y][threadIdx.x] = 0.0f;
    }

    // Synchronize to make sure the tile is loaded
    __syncthreads();

    // Multiply the two tiles together
    #pragma unroll
    for (int k = 0; k < TILE_SIZE; ++k) {
      sum += tile_A[threadIdx.y][k] * tile_B[k][threadIdx.x];
    }

    // Avoid extraneous synchronization in the final iteration
    if (tile != numTiles - 1) {
      __syncthreads();
    }
  }

  // Write the result (with bias and optional ReLU activation) to global memory
  if (row < batch_size && col < out_features) {
    float value = sum + bias[col];
    if (apply_relu) {
      value = value > 0.0f ? value : 0.0f;
    }
    output[row * out_features + col] = value;
  }
}

// The forward function applies a multi-layer perceptron (MLP) through a loop over layers.
// For each layer (except the final one), we use ReLU activation. The final layer omits ReLU.

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {
  // Assume x is a 2D tensor: [batch_size, features]
  auto x_current = x;

  // Process all layers except the last with ReLU activation
  for (size_t i = 0; i < weights.size() - 1; ++i) {
    int batch_size = x_current.size(0);
    int in_features = x_current.size(1);
    int out_features = weights[i].size(0);  // weight shape: [out_features, in_features]

    auto y = torch::empty({batch_size, out_features}, x_current.options());

    dim3 block(TILE_SIZE, TILE_SIZE);
    dim3 grid((out_features + TILE_SIZE - 1) / TILE_SIZE,
              (batch_size + TILE_SIZE - 1) / TILE_SIZE);

    bool apply_relu = true;

    mlp_layer_kernel<<<grid, block>>>(
        x_current.data_ptr<float>(),
        weights[i].data_ptr<float>(),
        biases[i].data_ptr<float>(),
        y.data_ptr<float>(),
        batch_size,
        in_features,
        out_features,
        apply_relu);

    // Wait for the kernel to finish execution before proceeding
    cudaDeviceSynchronize();

    x_current = y;
  }

  // Process the final layer without ReLU activation
  {
    int batch_size = x_current.size(0);
    int in_features = x_current.size(1);
    int out_features = weights.back().size(0);

    auto y = torch::empty({batch_size, out_features}, x_current.options());

    dim3 block(TILE_SIZE, TILE_SIZE);
    dim3 grid((out_features + TILE_SIZE - 1) / TILE_SIZE,
              (batch_size + TILE_SIZE - 1) / TILE_SIZE);

    bool apply_relu = false;

    mlp_layer_kernel<<<grid, block>>>(
        x_current.data_ptr<float>(),
        weights.back().data_ptr<float>(),
        biases.back().data_ptr<float>(),
        y.data_ptr<float>(),
        batch_size,
        in_features,
        out_features,
        apply_relu);

    cudaDeviceSynchronize();

    return y;
  }
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("forward", &forward, "Optimized MLP forward with minimal synchronizations");
}

#include <torch/extension.h>
#include <cuda_runtime.h>
