// Simple macro for error checking
#define CUDA_CHECK_ERRORS(call)                                \
  do {                                                         \
    cudaError_t err = call;                                    \
    if (err != cudaSuccess) {                                \
      printf("CUDA error %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
      exit(err);                                             \
    }                                                        \
  } while (0)

// Kernel for a dense layer with ReLU activation
__global__ void dense_relu_kernel(const float* __restrict__ input,
                                   const float* __restrict__ weight,
                                   const float* __restrict__ bias,
                                   float* __restrict__ output,
                                   int M, int K, int N) {
  int row = blockIdx.y * blockDim.y + threadIdx.y; // batch index
  int col = blockIdx.x * blockDim.x + threadIdx.x; // output feature index
  if (row < M && col < N) {
    float sum = 0.0f;
    for (int k = 0; k < K; ++k) {
      sum += input[row * K + k] * weight[col * K + k];
    }
    sum += bias[col];
    output[row * N + col] = sum > 0.0f ? sum : 0.0f;
  }
}

// Kernel for a dense layer without activation (final layer)
__global__ void dense_linear_kernel(const float* __restrict__ input,
                                     const float* __restrict__ weight,
                                     const float* __restrict__ bias,
                                     float* __restrict__ output,
                                     int M, int K, int N) {
  int row = blockIdx.y * blockDim.y + threadIdx.y;
  int col = blockIdx.x * blockDim.x + threadIdx.x;
  if (row < M && col < N) {
    float sum = 0.0f;
    for (int k = 0; k < K; ++k) {
      sum += input[row * K + k] * weight[col * K + k];
    }
    output[row * N + col] = sum + bias[col];
  }
}

// Forward function using CUDA streams to overlap computation with memory transfers
// Assumptions:
//   - Input tensor x resides in pinned host memory
//   - Weight and bias tensors are on the GPU
//   - This example implements an MLP with an arbitrary number of layers,
//     where all hidden layers use ReLU and the final layer is linear.

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {
  // x: [total, input_features] (on CPU, pinned memory recommended)
  int64_t total = x.size(0);
  int64_t input_features = x.size(1);

  // Get network dimensions from the first and last layer
  int hidden = static_cast<int>(weights[0].size(0));
  int output_features = static_cast<int>(weights.back().size(0));

  // Allocate output tensor on CPU
  auto out = torch::empty({total, output_features}, x.options());

  // Define chunk size for pipelining
  int chunk_size = 256;  // adjust based on workload

  // Create two CUDA streams: one for memory copies and one for computation
  cudaStream_t stream_copy, stream_compute;
  CUDA_CHECK_ERRORS(cudaStreamCreate(&stream_copy));
  CUDA_CHECK_ERRORS(cudaStreamCreate(&stream_compute));

  // Allocate double buffers on the device for input chunks
  float* d_chunk[2];
  size_t in_buffer_bytes = chunk_size * input_features * sizeof(float);
  CUDA_CHECK_ERRORS(cudaMalloc(&d_chunk[0], in_buffer_bytes));
  CUDA_CHECK_ERRORS(cudaMalloc(&d_chunk[1], in_buffer_bytes));

  // Create events to synchronize copy and compute streams
  cudaEvent_t event_copy[2];
  CUDA_CHECK_ERRORS(cudaEventCreate(&event_copy[0]));
  CUDA_CHECK_ERRORS(cudaEventCreate(&event_copy[1]));

  // Process the input in chunks
  for (int i = 0; i < total; i += chunk_size) {
    int current_chunk = std::min(chunk_size, (int)(total - i));
    int buf_idx = (i / chunk_size) % 2;

    // Async copy chunk from host (x) to device buffer d_chunk[buf_idx]
    const float* h_in = x.data_ptr<float>() + i * input_features;
    CUDA_CHECK_ERRORS(cudaMemcpyAsync(d_chunk[buf_idx], h_in,
                      current_chunk * input_features * sizeof(float),
                      cudaMemcpyHostToDevice, stream_copy));
    CUDA_CHECK_ERRORS(cudaEventRecord(event_copy[buf_idx], stream_copy));

    // Ensure the compute stream waits until the copy is done
    CUDA_CHECK_ERRORS(cudaStreamWaitEvent(stream_compute, event_copy[buf_idx], 0));

    // Pipeline the MLP layers on this chunk
    float* d_intermediate = d_chunk[buf_idx];  // device memory containing current chunk input
    float* d_temp = nullptr;
    int M = current_chunk;
    int K = static_cast<int>(input_features);

    // Process each layer sequentially for the current chunk
    for (size_t layer = 0; layer < weights.size(); ++layer) {
      int N = static_cast<int>(weights[layer].size(0));  // output dimension for this layer

      // Allocate temporary output buffer for this layer
      CUDA_CHECK_ERRORS(cudaMalloc(&d_temp, M * N * sizeof(float)));

      dim3 block(16, 16);
      dim3 grid((N + block.x - 1) / block.x, (M + block.y - 1) / block.y);
      if (layer < weights.size() - 1) {
        // Hidden layer: use ReLU activation
        dense_relu_kernel<<<grid, block, 0, stream_compute>>>(
            d_intermediate,
            weights[layer].data_ptr<float>(),
            biases[layer].data_ptr<float>(),
            d_temp,
            M,  // number of samples in chunk
            K,  // input dimension for this layer
            N   // output dimension for this layer
        );
      } else {
        // Final layer: linear (no activation)
        dense_linear_kernel<<<grid, block, 0, stream_compute>>>(
            d_intermediate,
            weights[layer].data_ptr<float>(),
            biases[layer].data_ptr<float>(),
            d_temp,
            M,
            K,
            N
        );
      }
      // Free the previous intermediate buffer if it was dynamically allocated (not one of our double-buffers)
      if (layer > 0) {
        CUDA_CHECK_ERRORS(cudaFree(d_intermediate));
      }
      d_intermediate = d_temp;
      K = N;  // update input dimension for next layer
    }
    // d_intermediate now points to the final output for this chunk
    float* h_out = out.data_ptr<float>() + i * output_features;
    CUDA_CHECK_ERRORS(cudaMemcpyAsync(h_out, d_intermediate,
                      M * output_features * sizeof(float),
                      cudaMemcpyDeviceToHost, stream_copy));
    // Free the final intermediate buffer
    CUDA_CHECK_ERRORS(cudaFree(d_intermediate));
  }

  // Synchronize streams to ensure all operations are complete
  CUDA_CHECK_ERRORS(cudaStreamSynchronize(stream_copy));
  CUDA_CHECK_ERRORS(cudaStreamSynchronize(stream_compute));

  // Clean-up
  CUDA_CHECK_ERRORS(cudaFree(d_chunk[0]));
  CUDA_CHECK_ERRORS(cudaFree(d_chunk[1]));
  CUDA_CHECK_ERRORS(cudaEventDestroy(event_copy[0]));
  CUDA_CHECK_ERRORS(cudaEventDestroy(event_copy[1]));
  CUDA_CHECK_ERRORS(cudaStreamDestroy(stream_copy));
  CUDA_CHECK_ERRORS(cudaStreamDestroy(stream_compute));

  return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("forward", &forward, "MLP forward with CUDA streams pipeline");
}

