    x = torch::linear(x, weights[i], biases[i]);
    int size = x.numel();
    int threads = 256;
    int blocks = (size + threads - 1) / threads;
    relu_activation<<<blocks, threads>>>(x.data_ptr<float>(), size);
  }
  x = torch::linear(x, weights.back(), biases.back());
  return x;
}

