#include <torch/extension.h>
#include <cuda_runtime.h>
#include <vector>

// Kernel that computes one dense layer (matrix multiply + bias + optional ReLU)
// Each thread computes one element of the output, with no shared memory usage
// and therefore no __syncthreads() calls.
__global__ void dense_nosync_kernel(const float* __restrict__ input,
                                     const float* __restrict__ weight,
                                     const float* __restrict__ bias,
                                     float* __restrict__ output,
                                     int batch_size,
                                     int in_features,
                                     int out_features,
                                     bool apply_relu) {
    // Map each thread to an output element
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < batch_size && col < out_features) {
        float sum = 0.0f;
        // Compute dot product for the (row, col) output element
        for (int k = 0; k < in_features; ++k) {
            sum += input[row * in_features + k] * weight[col * in_features + k];
        }
        // Add bias
        sum += bias[col];
        // Apply ReLU activation if required
        if (apply_relu) {
            sum = sum > 0.0f ? sum : 0.0f;
        }
        output[row * out_features + col] = sum;
    }
}

// Forward function that applies an MLP using the custom non-synchronizing kernel
// It sequentially applies each layer. For each layer, one kernel launch computes
// the dense transformation and optional ReLU activation without any shared memory
// synchronization, reducing overhead.

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  // x assumed to be a 2D tensor: [batch_size, features]
  // Sequentially apply all layers in the MLP
  for (size_t i = 0; i < weights.size() - 1; ++i) {
    int batch_size = x.size(0);
    int in_features = x.size(1);
    int out_features = weights[i].size(0); // weight shape: [out_features, in_features]

    auto y = torch::empty({batch_size, out_features}, x.options());

    dim3 block(16, 16);
    dim3 grid((out_features + block.x - 1) / block.x,
              (batch_size   + block.y - 1) / block.y);

    bool apply_relu = true;
    dense_nosync_kernel<<<grid, block>>>(
        x.data_ptr<float>(),
        weights[i].data_ptr<float>(),
        biases[i].data_ptr<float>(),
        y.data_ptr<float>(),
        batch_size, in_features, out_features,
        apply_relu
    );
