#include <torch/extension.h>

#define TILE_SIZE 32

__global__ void fused_linear_relu_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* output,
    int in_features,
    int out_features,
    int batch_size) {

    __shared__ float tile_A[TILE_SIZE][TILE_SIZE];
    __shared__ float tile_B[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float sum = 0.0f;

    for (int t = 0; t < (in_features + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        int tiled_col = t * TILE_SIZE + threadIdx.x;
        if (row < batch_size && tiled_col < in_features)
            tile_A[threadIdx.y][threadIdx.x] = input[row * in_features + tiled_col];
        else
            tile_A[threadIdx.y][threadIdx.x] = 0.0f;

        int weight_col = t * TILE_SIZE + threadIdx.y;
        if (col < out_features && weight_col < in_features)
            tile_B[threadIdx.y][threadIdx.x] = weight[col * in_features + weight_col];
        else
            tile_B[threadIdx.y][threadIdx.x] = 0.0f;

        __syncthreads();

        for (int k = 0; k < TILE_SIZE; ++k)
            sum += tile_A[threadIdx.y][k] * tile_B[k][threadIdx.x];

        __syncthreads();
    }

    if (row < batch_size && col < out_features) {
        float val = sum + bias[col];
        output[row * out_features + col] = val > 0.0f ? val : 0.0f;
    }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    for (size_t i = 0; i < weights.size() - 1; ++i) {
        int batch_size = x.size(0);
        int in_features = weights[i].size(1);
        int out_features = weights[i].size(0);

        auto output = torch::empty({batch_size, out_features}, x.options());

        dim3 blocks(
            (out_features + TILE_SIZE - 1) / TILE_SIZE,
            (batch_size + TILE_SIZE - 1) / TILE_SIZE
        );
        dim3 threads(TILE_SIZE, TILE_SIZE);

        fused_linear_relu_kernel<<<blocks, threads>>>(
            x.data_ptr<float>(),
            weights[i].data_ptr<float>(),
            biases[i].data_ptr<float>(),
            output.data_ptr<float>(),
            in_features,
            out_features,
            batch_size
        );

        x = output;
    }

    // Final layer without ReLU
    x = torch::linear(x, weights.back(), biases.back());
    return x;
}

