// Fused kernel to perform a linear transformation and optional ReLU activation.
// The kernel evenly distributes workload across threads using a grid-stride loop.

__global__ void fused_linear_layer_kernel(
    const float* __restrict__ input,
    float* __restrict__ output,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    int M, // batch size
    int K, // input features
    int N, // output features
    bool apply_relu) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  int stride = blockDim.x * gridDim.x;

  // Each thread processes multiple output elements in a grid-stride loop
  for (int i = idx; i < M * N; i += stride) {
    int m = i / N; // batch index
    int n = i % N; // output feature index
    float sum = 0.0f;

    // Compute dot product for the linear layer
    for (int k = 0; k < K; k++) {
      sum += input[m * K + k] * weight[n * K + k];
    }
    sum += bias[n];

    // Apply ReLU if this is not the final layer
    if (apply_relu) {
      sum = fmaxf(sum, 0.0f);
    }

    output[m * N + n] = sum;
  }
}

// Forward function fusing linear layer and ReLU activation where applicable.
// For each layer in the MLP, we launch a kernel that computes: y = max(0, x * W^T + b) for intermediate layers,
// and y = x * W^T + b for the final layer.

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  // Assume x is a contiguous float tensor of shape [M, K]
  torch::Tensor input_tensor = x;

  // Iterate over each layer
  for (size_t i = 0; i < weights.size(); i++) {
    auto weight = weights[i];   // Expected shape: [N, K] (row-major)
    auto bias = biases[i];      // Expected shape: [N]

    int M = input_tensor.size(0);
    int K = input_tensor.size(1);
    int N = weight.size(0);

    // Allocate output tensor for current layer
    auto output_tensor = torch::empty({M, N}, input_tensor.options());

    int total = M * N;
    int threads = 256;  
    int blocks = (total + threads - 1) / threads;

    // Apply ReLU for intermediate layers only
    bool apply_relu = (i < weights.size() - 1);

    fused_linear_layer_kernel<<<blocks, threads>>>(
        input_tensor.data_ptr<float>(),
        output_tensor.data_ptr<float>(),
        weight.data_ptr<float>(),
        bias.data_ptr<float>(),
        M, K, N, apply_relu);

    // Use the output as the input for the next layer
    input_tensor = output_tensor;
  }

  return input_tensor;
}

