// This kernel fuses the linear (matrix multiply + bias addition) and ReLU activation into one.
// Each thread processes one or more output elements (grid-stride loop) to distribute the workload evenly.

__global__ void linear_relu_kernel(const float* A, const float* B, const float* bias, float* C, int N, int K, int M) {
    // C has shape [N, M] computed as: C[n, m] = dot(A[n, :], B[m, :]) + bias[m] then ReLU
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * M;
    for (int i = idx; i < total; i += blockDim.x * gridDim.x) {
        int row = i / M;
        int col = i % M;
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            sum += A[row * K + k] * B[col * K + k];
        }
        // Apply bias and ReLU activation
        C[i] = fmaxf(sum + bias[col], 0.0f);
    }
}

__global__ void linear_kernel(const float* A, const float* B, const float* bias, float* C, int N, int K, int M) {
    // This kernel computes only the linear transformation (without activation)
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * M;
    for (int i = idx; i < total; i += blockDim.x * gridDim.x) {
        int row = i / M;
        int col = i % M;
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            sum += A[row * K + k] * B[col * K + k];
        }
        C[i] = sum + bias[col];
    }
}

// The forward function iterates over MLP layers, fusing the linear and ReLU operations for hidden layers
// and performing only the linear transformation for the final layer.

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    for (size_t i = 0; i < weights.size(); i++) {
        int N = x.size(0);
        int K = x.size(1);                // input features
        int M = weights[i].size(0);         // output features (weights assumed to be [M, K])
        auto y = torch::empty({N, M}, x.options());

        int total = N * M;
        int threads = 256;
        int blocks = (total + threads - 1) / threads;

        float* A = x.data_ptr<float>();
        float* B = weights[i].data_ptr<float>();
        float* bias_ptr = biases[i].data_ptr<float>();
        float* C = y.data_ptr<float>();

        if (i < weights.size() - 1) {
            // For hidden layers: fuse linear + bias + ReLU
            linear_relu_kernel<<<blocks, threads>>>(A, B, bias_ptr, C, N, K, M);
        } else {
            // For the final layer: only linear transformation
            linear_kernel<<<blocks, threads>>>(A, B, bias_ptr, C, N, K, M);
        }
        x = y;  // propagate output as input for next layer
    }
    return x;
}

