__global__ void linear_layer(float* x, const float* weight, const float* bias, float* output, int in_features, int out_features) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    for (int i = idx; i < out_features; i += stride) {
        float sum = 0.0f;
        for (int j = 0; j < in_features; ++j) {
            sum += x[j] * weight[i * in_features + j];
        }
        output[i] = sum + bias[i];
    }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
