    linear_layer<<<blocks, threads>>>(x_flat.data_ptr<float>(), weights[i].data_ptr<float>(), biases[i].data_ptr<float>(), output.data_ptr<float>(), in_features, out_features);

    int size = output.numel();
    relu_activation<<<blocks, threads>>>(output.data_ptr<float>(), size);
    x = output;
