__global__ void fused_linear_relu_optimized_kernel(const float* __restrict__ x,
                                                    const float* __restrict__ weight,
                                                    const float* __restrict__ bias,
                                                    float* __restrict__ y,
                                                    int batch_size, int in_features, int out_features) {
    int row = blockIdx.y * TILE + threadIdx.y;
    int col = blockIdx.x * TILE + threadIdx.x;

    float acc = 0.0f;

    // Shared memory tiles for input and weight
    __shared__ float s_x[TILE][TILE];
    __shared__ float s_w[TILE][TILE];

    // Loop over all tiles along the in_features dimension
    for (int t = 0; t < (in_features + TILE - 1) / TILE; t++) {
        int x_col = t * TILE + threadIdx.x;
        if (row < batch_size && x_col < in_features) {
            s_x[threadIdx.y][threadIdx.x] = x[row * in_features + x_col];
        } else {
            s_x[threadIdx.y][threadIdx.x] = 0.0f;
