        int w_col = t * TILE + threadIdx.y;
        if (col < out_features && w_col < in_features) {
            s_w[threadIdx.y][threadIdx.x] = weight[col * in_features + w_col];
        } else {
            s_w[threadIdx.y][threadIdx.x] = 0.0f;
        }

        // Synchronize to ensure the tile is fully loaded
        __syncthreads();

        // Multiply the two tiles
        #pragma unroll
        for (int k = 0; k < TILE; k++) {
            acc += s_x[threadIdx.y][k] * s_w[k][threadIdx.x];
