#include <torch/extension.h>

// Fused kernel: performs linear transformation and ReLU activation in one pass
__global__ void fused_linear_relu_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int batch_size,
    int in_features,
    int out_features) {

  // Each thread computes one element of the output matrix
  int col = blockIdx.x * blockDim.x + threadIdx.x;
  int row = blockIdx.y * blockDim.y + threadIdx.y;

  if (row < batch_size && col < out_features) {
    float acc = 0.0f;
    // Compute dot product for one output element
    for (int k = 0; k < in_features; ++k) {
      acc += input[row * in_features + k] * weight[col * in_features + k];
    }
    // Add bias and apply ReLU activation
    acc += bias[col];
    output[row * out_features + col] = fmaxf(acc, 0.0f);
  }
}

// Fused linear + ReLU function for intermediate layers
torch::Tensor fused_linear_relu(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias) {
  // Assume input is 2D: [batch_size, in_features]
  int batch_size = input.size(0);
  int in_features = input.size(1);
  int out_features = weight.size(0);

  auto output = torch::empty({batch_size, out_features}, input.options());

  // Use a 2D grid to evenly distribute computation over rows and columns
  dim3 block(16, 16);
  dim3 grid((out_features + block.x - 1) / block.x, (batch_size + block.y - 1) / block.y);

  fused_linear_relu_kernel<<<grid, block>>>(
      input.data_ptr<float>(),
      weight.data_ptr<float>(),
      bias.data_ptr<float>(),
      output.data_ptr<float>(),
      batch_size,
      in_features,
      out_features);

  return output;
}

// Forward function for a multi-layer perceptron
// Fuses linear and ReLU for all but the last layer to reduce kernel launch overhead
torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  // For each hidden layer, use the fused linear + ReLU kernel
  for (size_t i = 0; i < weights.size() - 1; ++i) {
    x = fused_linear_relu(x, weights[i], biases[i]);
  }
  // For the final layer, apply linear transformation without ReLU
  x = torch::linear(x, weights.back(), biases.back());
  return x;
}

