#include <torch/extension.h>

__global__ void mlp_forward_kernel(
    float* output,
    const float* input,
    const float* weights,
    const float* bias,
    const int batch_size,
    const int input_dim,
    const int output_dim) {

    const int tid = blockIdx.x * blockDim.x + threadIdx.x;
    const int stride = blockDim.x * gridDim.x;

    // Iterate over all elements with stride
    for (int idx = tid; idx < batch_size * output_dim; idx += stride) {
        const int batch_idx = idx / output_dim;
        const int out_idx = idx % output_dim;

        float sum = bias[out_idx];
        for (int i = 0; i < input_dim; i++) {
            sum += input[batch_idx * input_dim + i] * 
                   weights[out_idx * input_dim + i];
        }
        output[idx] = sum > 0 ? sum : 0; // ReLU activation
    }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    const int batch_size = x.size(0);
    torch::Tensor current = x;

    for (size_t layer = 0; layer < weights.size() - 1; ++layer) {
        const int input_dim = current.size(1);
        const int output_dim = weights[layer].size(0);

        auto output = torch::empty({batch_size, output_dim}, 
                                 current.options());

        const int threads = 256;
        const int blocks = (batch_size * output_dim + threads - 1) / threads;

        mlp_forward_kernel<<<blocks, threads>>>(
            output.data_ptr<float>(),
            current.data_ptr<float>(),
            weights[layer].data_ptr<float>(),
            biases[layer].data_ptr<float>(),
            batch_size,
            input_dim,
            output_dim
        );

        current = output;
    }

    // Final layer without ReLU
    const int input_dim = current.size(1);
    const int output_dim = weights.back().size(0);
    auto output = torch::linear(current, weights.back(), biases.back());

    return output;
}

