__global__ void mlp_forward_kernel(float* x, float* weights, float* biases, int input_size, int output_size, int layers) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx < output_size) {
    float sum = 0.0f;

    #pragma unroll
    for (int j = 0; j < input_size; ++j) {
      sum += x[j] * weights[j * output_size + idx];
    }
    x[idx] = sum + biases[idx];

    if (layers > 1) {
      x[idx] = x[idx] > 0 ? x[idx] : 0; // ReLU activation
    }
  }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  auto device = x.device();
  auto output_size = weights.back().size(0);
  auto input_size = x.size(1);

  dim3 block(256);
  dim3 grid((output_size + block.x - 1) / block.x);

  float* d_x = x.data_ptr<float>();
  float* d_weights = weights[0].data_ptr<float>();
  float* d_biases = biases[0].data_ptr<float>();

  mlp_forward_kernel<<<grid, block>>>(d_x, d_weights, d_biases, input_size, output_size, weights.size());

  x = torch::from_blob(d_x, {output_size}, x.options()).to(device);
  return x;
}

