__global__ void linear_kernel(const float* __restrict__ input,
                              const float* __restrict__ weight,
                              const float* __restrict__ bias,
                              float* output,
                              int M, int N, int K) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; ++k) {
            sum += __ldg(&input[row * K + k]) * __ldg(&weight[k * N + col]);
        }
        output[row * N + col] = sum + __ldg(&bias[col]);
    }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  int batch_size = x.size(0);
  int in_features = x.size(1);

  for (size_t i = 0; i < weights.size() - 1; ++i) {
    int out_features = weights[i].size(0);
    auto y = torch::empty({batch_size, out_features}, x.options());

    dim3 block(16, 16);
    dim3 grid((out_features + block.x - 1) / block.x, (batch_size + block.y - 1) / block.y);

    linear_kernel<<<grid, block>>>(
        x.data_ptr<float>(),
        weights[i].data_ptr<float>(),
        biases[i].data_ptr<float>(),
        y.data_ptr<float>(),
        batch_size,
        out_features,
        in_features);

    int size = y.numel();
    int threads = 256;
    int blocks = (size + threads - 1) / threads;
    relu_activation<<<blocks, threads>>>(y.data_ptr<float>(), size);

    x = y;
  }

  int out_features = weights.back().size(0);
  auto y = torch::empty({batch_size, out_features}, x.options());

  dim3 block(16, 16);
  dim3 grid((out_features + block.x - 1) / block.x, (batch_size + block.y - 1) / block.y);

  linear_kernel<<<grid, block>>>(
      x.data_ptr<float>(),
      weights.back().data_ptr<float>(),
      biases.back().data_ptr<float>(),
      y.data_ptr<float>(),
      batch_size,
      out_features,
      in_features);

  return y;
}

