    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    // Create streams
    auto compute_stream = at::cuda::getStreamFromPool();
    auto transfer_stream = at::cuda::getStreamFromPool();

    // Pin memory and transfer input asynchronously
    auto x_pinned = x.pin_memory();
    auto x_device = x_pinned.to(weights[0].device(), false, true);

    at::cuda::CUDAStreamGuard guard(compute_stream);

    for (size_t i = 0; i < weights.size() - 1; ++i) {
        // Linear operation
        x_device = torch::linear(x_device, weights[i], biases[i]);

        // ReLU activation
        int size = x_device.numel();
        int threads = 256;
        int blocks = (size + threads - 1) / threads;

        relu_activation<<<blocks, threads, 0, compute_stream>>>(
            x_device.data_ptr<float>(), size);
    }

    // Final linear layer
    x_device = torch::linear(x_device, weights.back(), biases.back());

    // Asynchronous transfer back to CPU with stream synchronization
    auto result = x_device.to(x.device(), false, true);

    // Ensure all operations are complete
    compute_stream.synchronize();
    transfer_stream.synchronize();

    return result;
}

