__global__ void linear_layer_with_shared_memory(float* x, const float* weight, const float* bias, int in_features, int out_features, int batch_size) {
    extern __shared__ float shared_data[];
    int tx = threadIdx.x;
    int row = blockIdx.x;
    int col = threadIdx.x;

    if (row < batch_size && col < out_features) {
        float sum = 0.0f;
        for (int i = tx; i < in_features; i += blockDim.x) {
            sum += x[row * in_features + i] * weight[col * in_features + i];
        }
        shared_data[tx] = sum;
        __syncthreads();

        // Reduce within the block
        for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
            if (tx < stride) {
                shared_data[tx] += shared_data[tx + stride];
            }
            __syncthreads();
        }

        if (tx == 0) {
            float result = shared_data[0] + bias[col];
            x[row * out_features + col] = result;
        }
    }
}

