    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  auto x_current = x;
  for (size_t i = 0; i < weights.size() - 1; ++i) {
    int batch_size = x_current.size(0);
    int in_features = x_current.size(1);
    int out_features = weights[i].size(0);

    int threads = 256;
    int blocks = batch_size;
    size_t shared_memory_size = threads * sizeof(float);

    linear_layer_with_shared_memory<<<blocks, threads, shared_memory_size>>>(
        x_current.data_ptr<float>(),
        weights[i].data_ptr<float>(),
        biases[i].data_ptr<float>(),
        in_features, out_features, batch_size);
    cudaDeviceSynchronize();

    int size = x_current.numel();
    blocks = (size + threads - 1) / threads;
    relu_activation<<<blocks, threads>>>(x_current.data_ptr<float>(), size);
  }

  // Final layer without ReLU
  x_current = torch::linear(x_current, weights.back(), biases.back());

  return x_current;
}

