#include <torch/extension.h>

__constant__ float const_weights[1024 * 1024];  // Assuming max size for demonstration
__constant__ float const_biases[1024];  // Assuming max size for demonstration

__global__ void relu_activation(float* x, int size) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < size) {
        x[idx] = fmaxf(0.0f, x[idx]);
    }
}

__global__ void linear_with_constant(float* x, int in_features, int out_features) {
    int row = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < out_features) {
        float sum = 0.0f;
        for (int k = 0; k < in_features; ++k) {
            sum += x[k] * const_weights[row * in_features + k];
        }
        x[row] = sum + const_biases[row];
    }
}

void copy_to_constant(const float* weights, const float* biases, int weight_size, int bias_size) {
    cudaMemcpyToSymbol(const_weights, weights, weight_size * sizeof(float));
    cudaMemcpyToSymbol(const_biases, biases, bias_size * sizeof(float));
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

  for (size_t i = 0; i < weights.size() - 1; ++i) {
    int in_features = x.size(1);
    int out_features = weights[i].size(0);

    copy_to_constant(weights[i].data_ptr<float>(), biases[i].data_ptr<float>(), in_features * out_features, out_features);

    int threads = 256;
    int blocks = (out_features + threads - 1) / threads;
    linear_with_constant<<<blocks, threads>>>(x.data_ptr<float>(), in_features, out_features);

    int size = x.numel();
    blocks = (size + threads - 1) / threads;
    relu_activation<<<blocks, threads>>>(x.data_ptr<float>(), size);
  }

  // Final layer
  int in_features = x.size(1);
  int out_features = weights.back().size(0);

  copy_to_constant(weights.back().data_ptr<float>(), biases.back().data_ptr<float>(), in_features * out_features, out_features);

  int threads = 256;
  int blocks = (out_features + threads - 1) / threads;
  linear_with_constant<<<blocks, threads>>>(x.data_ptr<float>(), in_features, out_features);

  return x;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("forward", &forward, "MLP forward with constant memory");
}

#include <torch/extension.h>
#include <cuda_runtime.h>

#define TILE 32
#define WARPS 4

__global__ void fused_mlp_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* output,
    int in_features,
    int out_features,
    bool apply_relu) {

    __shared__ float smem[TILE][TILE + 1];

    int row = blockIdx.y * TILE + threadIdx.y;
    int col = blockIdx.x * TILE + threadIdx.x;

    float sum = 0.0f;

    for (int t = 0; t < (in_features + TILE - 1) / TILE; ++t) {
        int load_col = t * TILE + threadIdx.x;
        if (row < gridDim.y * TILE && load_col < in_features)
            smem[threadIdx.y][threadIdx.x] = input[row * in_features + load_col];
        else
            smem[threadIdx.y][threadIdx.x] = 0;

        __syncthreads();

        for (int k = 0; k < TILE; k++) {
            float w = (t * TILE + k < in_features) ? 
                     weight[col * in_features + t * TILE + k] : 0;
            sum += smem[threadIdx.y][k] * w;
        }

        if (t < (in_features + TILE - 1) / TILE - 1)
            __syncthreads();
    }

    if (row < gridDim.y * TILE && col < out_features) {
        sum += bias[col];
        if (apply_relu) sum = fmaxf(sum, 0.0f);
        output[row * out_features + col] = sum;
    }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    for (size_t i = 0; i < weights.size() - 1; ++i) {
        auto y = torch::empty({x.size(0), weights[i].size(0)}, x.options());

        dim3 blocks(
            (weights[i].size(0) + TILE - 1) / TILE,
            (x.size(0) + TILE - 1) / TILE
        );
        dim3 threads(TILE, WARPS);

        fused_mlp_kernel<<<blocks, threads>>>(
            x.data_ptr<float>(),
            weights[i].data_ptr<float>(),
            biases[i].data_ptr<float>(),
            y.data_ptr<float>(),
            x.size(1),
            weights[i].size(0),
            true
        );

        x = y;
    }

    auto y = torch::empty({x.size(0), weights.back().size(0)}, x.options());
    dim3 blocks(
        (weights.back().size(0) + TILE - 1) / TILE,
        (x.size(0) + TILE - 1) / TILE
    );
    dim3 threads(TILE, WARPS);

    fused_mlp_kernel<<<blocks, threads>>>(
        x.data_ptr<float>(),
        weights.back().data_ptr<float>(),
        biases.back().data_ptr<float>(),
        y.data_ptr<float>(),
        x.size(1),
        weights.back().size(0),
        false
    );

    return y;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("forward", &forward, "Fused MLP with optimized synchronization");
}

#include <torch/extension.h>

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    // Get device properties
    cudaDeviceProp props;
    cudaGetDeviceProperties(&props, x.device().index());

    // Choose implementation based on tensor size and hardware
    for (size_t i = 0; i < weights.size() - 1; ++i) {
        x = torch::linear(x, weights[i], biases[i]);

        // For small tensors, use torch::relu to avoid kernel launch overhead
        if (x.numel() < 10000) {
            x = torch::relu(x);
        }
        // For larger tensors where memory bandwidth is critical, use custom kernel
        else {
            int size = x.numel();
            int threads = 256;
            int blocks = (size + threads - 1) / threads;

            // Use inline PTX assembly for maximum efficiency
            auto relu_kernel = [] __device__ (float val) {
                float result;
                asm("max.f32 %0, %1, 0.0;" : "=f"(result) : "f"(val));
                return result;
            };

            x = x.map(relu_kernel);
        }
    }
    x = torch::linear(x, weights.back(), biases.back());
    return x;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("forward", &forward, "MLP forward");
}

#include <torch/extension.h>
#include <vector>

#define TILE_SIZE 32  // Increased from 16 for better occupancy
#define WARP_SIZE 32

template<typename T>
__device__ __forceinline__ T warp_reduce_sum(T val) {
    #pragma unroll
    for (int offset = WARP_SIZE/2; offset > 0; offset /= 2) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    return val;
}

__global__ void mlp_layer_fused_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* output,
    int batch_size,
    int in_features,
    int out_features,
    bool apply_relu,
    float* __restrict__ workspace = nullptr) {

    __shared__ float tile_input[TILE_SIZE][TILE_SIZE + 1];  // +1 for bank conflicts
    __shared__ float tile_weight[TILE_SIZE][TILE_SIZE + 1];

    const int tid = threadIdx.x + threadIdx.y * blockDim.x;
    const int wid = tid / WARP_SIZE;
    const int lane = tid % WARP_SIZE;

    const int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    const int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float sum = 0.0f;

    for (int tile = 0; tile < (in_features + TILE_SIZE - 1) / TILE_SIZE; ++tile) {
        const int input_col = tile * TILE_SIZE + threadIdx.x;
        if (row < batch_size && input_col < in_features) {
            tile_input[threadIdx.y][threadIdx.x] = input[row * in_features + input_col];
        } else {
            tile_input[threadIdx.y][threadIdx.x] = 0.0f;
        }

        const int weight_row = tile * TILE_SIZE + threadIdx.y;
        if (col < out_features && weight_row < in_features) {
            tile_weight[threadIdx.y][threadIdx.x] = weight[col * in_features + weight_row];
        } else {
            tile_weight[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += tile_input[threadIdx.y][k] * tile_weight[k][threadIdx.x];
        }

        __syncthreads();
    }

    if (row < batch_size && col < out_features) {
        sum = warp_reduce_sum(sum);
        if (lane == 0) {
            float final_value = sum + bias[col];
            if (apply_relu) {
                final_value = max(0.0f, final_value);
            }
            output[row * out_features + col] = final_value;
        }
    }
}

torch::Tensor forward(
    torch::Tensor x,
    const std::vector<torch::Tensor>& weights,
    const std::vector<torch::Tensor>& biases) {

    auto current = x;

    for (size_t i = 0; i < weights.size(); ++i) {
        const int batch_size = current.size(0);
        const int in_features = current.size(1);
        const int out_features = weights[i].size(0);

        auto output = torch::empty({batch_size, out_features}, current.options());

        dim3 block(TILE_SIZE, TILE_SIZE);
        dim3 grid((out_features + TILE_SIZE - 1) / TILE_SIZE,
                  (batch_size + TILE_SIZE - 1) / TILE_SIZE);

        const bool apply_relu = (i < weights.size() - 1);

        mlp_layer_fused_kernel<<<grid, block>>>(
            current.data_ptr<float>(),
            weights[i].data_ptr<float>(),
            biases[i].data_ptr<float>(),
            output.data_ptr<float>(),
            batch_size,
            in_features,
            out_features,
            apply_relu);

        current = output;
    }

    return current;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("forward", &forward, "Optimized MLP forward with fused operations");
}
